return ['domain'=>'agnosis','plural-forms'=>'nplurals=2; plural=n > 1;','language'=>'fr_FR','project-id-version'=>'Agnosis 0.9.21','pot-creation-date'=>'2026-07-12T16:27+00:00','po-revision-date'=>'2026-07-12 17:44+0000','x-generator'=>'Loco https://localise.biz/','messages'=>['Agnosis'=>'Agnosis','https://agnosis.art'=>'https://agnosis.art','Art blooming out of oblivion. Email your art, AI polishes it, the world sees it. A free, federated publishing network for independent artists.'=>'L’art qui émerge de l’oubli. Envoyez votre art par e-mail, l’IA le sublime, le monde le découvre. Un réseau de publication libre et fédéré pour les artistes indépendants.','Agnosis Network'=>'Agnosis Network','Agnosis requires PHP %s or higher.'=>'Agnosis nécessite PHP %s ou une version supérieure.','Agnosis requires WordPress %s or higher.'=>'Agnosis nécessite WordPress %s ou une version supérieure.','Filter by medium'=>'Filtrer par médium','All'=>'Tout','Enlarged image'=>'Image agrandie','Featured'=>'Mis en avant','Enlarge'=>'Agrandir','Gallery pages'=>'Pages de la galerie','Prev'=>'Préc.','Next'=>'Suiv.','Contact Messages'=>'Messages de contact','No contact messages yet.'=>'Aucun message de contact pour le moment.','No messages match this filter.'=>'Aucun message ne correspond à ce filtre.','#'=>'#','Artist'=>'Artiste','From'=>'De','Message'=>'Message','Status'=>'Statut','Received'=>'Reçu','Actions'=>'Actions','(deleted artist #%d)'=>'(artiste supprimé #%d)','You do not have permission to perform this action.'=>'Vous n’avez pas l’autorisation d’effectuer cette action.','Message deleted.'=>'Message supprimé.','All statuses'=>'Tous les statuts','Sent'=>'Envoyé','Rejected'=>'Rejeté','Filter'=>'Filtrer','Reset'=>'Réinitialiser','Page %1$d of %2$d'=>'Page %1$d sur %2$d','Previous'=>'Précédent','Delete this message?'=>'Supprimer ce message ?','Delete'=>'Supprimer','just now'=>'à l’instant','%dm ago'=>'il y a %d min','%dh ago'=>'il y a %d h','Mail from (workflow)'=>'Mail from (workflow)','Newsletter'=>'Newsletter','Agnosis Inbox'=>'Boîte de réception Agnosis','Inbox'=>'Boîte de réception','No messages in the queue yet. Click "Poll Inbox" to fetch messages from your IMAP account.'=>'Aucun message dans la file pour le moment. Cliquez sur « Relever la boîte de réception » pour récupérer les messages de votre compte IMAP.','No queue rows match this filter.'=>'Aucune ligne de la file ne correspond à ce filtre.','Subject'=>'Objet','Endpoint'=>'Point de terminaison','Files'=>'Fichiers','Error'=>'Erreur','unregistered sender'=>'expéditeur non enregistré','Old row — delete and re-poll to preview'=>'Ancienne ligne — supprimer puis relancer la récupération pour prévisualiser','Attachment viewer'=>'Visionneuse de pièces jointes','Close'=>'Fermer','Queue row deleted. Poll Inbox to re-fetch the message.'=>'Ligne de file supprimée. Interrogez la boîte de réception pour récupérer à nouveau le message.','Queue #%d sent to pipeline. Check back in a few seconds.'=>'La file n°%d a été envoyée au pipeline. Revenez dans quelques secondes.','Poll complete. %d new message(s) added to the queue.'=>'Récupération terminée. %d nouveau(x) message(s) ajoutés à la file.','Force-reprocess: %1$d row(s) reset, %2$d new message(s) enqueued.'=>'Forçage du retraitement : %1$d ligne(s) réinitialisée(s), %2$d nouveau(x) message(s) ajoutés à la file.','Processed %d pending item(s).'=>'%d élément(s) en attente traité(s).','Pending'=>'En attente','Processing'=>'Traitement en cours','Published'=>'Publié','Failed'=>'Échec','Skipped'=>'Ignoré','All reasons'=>'Toutes les raisons','%1$d message from an unregistered sender is hidden from this view. <a href="%2$s">View it</a>.'=>'%1$d message d’un expéditeur non enregistré est masqué dans cette vue. <a href="%2$s">Le voir</a>.' . "\0" . '%1$d messages d’expéditeurs non enregistrés sont masqués dans cette vue. <a href="%2$s">Les voir</a>.','Poll Inbox'=>'Interroger la boîte de réception','Force Reprocess'=>'Forcer le retraitement','Process All Pending'=>'Traiter tous les éléments en attente','Goodbye'=>'Au revoir','Community'=>'Communauté','Bounce'=>'Rebond','Awaiting Review'=>'En attente de révision','Live'=>'En ligne','Processed'=>'Traité','Member Removed'=>'Membre supprimé','Broadcast Sent'=>'Diffusion envoyée','Bounced (too long)'=>'Rebondi (trop long)','Handled'=>'Géré','Process'=>'Traiter','View Post'=>'Voir la publication','Reprocess'=>'Retraiter','Running…'=>'En cours…','Delete this queue row?'=>'Supprimer cette ligne de file ?','Configuration'=>'Configuration','Force-reprocess complete. %1$d queue row(s) reset, %2$d new message(s) enqueued. Click "Process Pending Queue" to run the AI pipeline.'=>'Forçage du retraitement terminé. %1$d ligne(s) de file réinitialisée(s), %2$d nouveau(x) message(s) ajoutés à la file. Cliquez sur « Traiter la file en attente » pour lancer le pipeline IA.','Log cleared.'=>'Journal effacé.','Debug files cleared. %d file was removed.'=>'Fichiers de débogage effacés. %d fichier a été supprimé.' . "\0" . 'Fichiers de débogage effacés. %d fichiers ont été supprimés.','Term translation cache cleared. Terms will be re-translated the next time they\'re needed.'=>'Cache de traduction des termes effacé. Les termes seront retraduits la prochaine fois qu\'ils seront nécessaires.','Processed %d pending queue item(s). Check the Logs tab for details.'=>'%d élément(s) de la file en attente traité(s). Consultez l’onglet Journaux pour plus de détails.','Poll complete. %d new message(s) enqueued. Check the Logs tab, then click Process Pending Queue.'=>'Récupération terminée. %d nouveau(x) message(s) ajoutés à la file. Consultez l’onglet Journaux, puis cliquez sur Traiter la file en attente.','Applicant admitted. A welcome email has been sent.'=>'Candidat admis. Un e-mail de bienvenue a été envoyé.','Could not admit — the application may no longer be pending.'=>'Impossible d’admettre — la candidature n’est peut-être plus en attente.','Application rejected.'=>'Candidature rejetée.','Could not reject — the application may no longer be pending.'=>'Impossible de rejeter — la candidature n’est peut-être plus en attente.','Artist suspended. A notification email has been sent.'=>'Artiste suspendu. Un e-mail de notification a été envoyé.','Could not suspend the artist — they may no longer be active.'=>'Impossible de suspendre l’artiste — il n’est peut-être plus actif.','Artist permanently deleted. Their account and all content have been removed.'=>'Artiste définitivement supprimé. Son compte et tout son contenu ont été supprimés.','Could not delete the artist — please try again.'=>'Impossible de supprimer l’artiste — veuillez réessayer.','Community removal vote opened. All artists have been emailed.'=>'Vote pour la suppression de la communauté ouvert. Tous les artistes ont été informés par e-mail.','Could not open a removal vote — one may already be active for this artist.'=>'Impossible d’ouvrir un vote pour la suppression — il y en a peut-être déjà un en cours pour cet artiste.','Issue prepared and queued — it will go out over the next few cron cycles.'=>'L’issue a été préparée et mise en file d’attente — elle sera envoyée au cours des prochains cycles cron.','Could not start this issue — a previous one may still be sending.'=>'Impossible de démarrer cette issue — une précédente est peut-être encore en cours d’envoi.','Test email sent — check the inbox you sent it to.'=>'E-mail de test envoyé — vérifiez la boîte de réception à laquelle vous l’avez envoyé.','Could not send the test email — check the address and your site\'s outgoing mail configuration.'=>'Impossible d’envoyer l’e-mail de test — vérifiez l’adresse et la configuration des e-mails sortants de votre site.','Invitation sent.'=>'Invitation envoyée.','Could not send the invitation — check the address and your site\'s outgoing mail configuration.'=>'Impossible d’envoyer l’invitation — vérifiez l’adresse et la configuration des e-mails sortants de votre site.','Test invitation sent — check the inbox you sent it to.'=>'Invitation de test envoyée — vérifiez la boîte de réception à laquelle vous l’avez envoyée.','Could not send the test invitation — check the address and your site\'s outgoing mail configuration.'=>'Impossible d’envoyer l’invitation de test — vérifiez l’adresse et la configuration des e-mails sortants de votre site.','Test email sent — check whether it lands in your inbox or your spam folder.'=>'E-mail de test envoyé — vérifiez s’il arrive dans votre boîte de réception ou dans votre dossier spam.','Failed recipients reset to pending — they will be retried on the next few cron cycles.'=>'Les destinataires en échec ont été réinitialisés à l’état en attente — ils seront retentés au cours des prochains cycles cron.','No failed recipients to retry for this newsletter.'=>'Aucun destinataire en échec à retenter pour cette newsletter.','Art blooming out of oblivion'=>'L’art fleurit hors de l’oubli','Save Changes'=>'Enregistrer les modifications','Members'=>'Membres','Rules'=>'Règles','General'=>'Général','Email Inbox'=>'Boîte de réception des e-mails','AI Providers'=>'Fournisseurs d’IA','Behavior'=>'Comportement','Network'=>'Réseau','Commerce'=>'Commerce','Logs'=>'Journaux','— None (inline message only) —'=>'— Aucun (message en ligne uniquement) —','Reset to default'=>'Réinitialiser par défaut','Replaces the text above with the plugin\'s built-in default — click Save Changes below to keep it.'=>'Remplace le texte ci-dessus par la valeur par défaut intégrée du plugin — cliquez sur « Enregistrer les modifications » ci-dessous pour la conserver.','Select Image'=>'Sélectionner une image','Remove'=>'Supprimer','Base domain'=>'Domaine de base','Root domain for artist subdomains, e.g. agnosis.art. Each artist is reachable at nicename.{base_domain}. Requires a wildcard DNS record (*.{base_domain}) pointing to this server. Leave blank to disable subdomain routing.'=>'Domaine racine pour les sous-domaines d’artistes, par ex. agnosis.art. Chaque artiste est accessible à nicename.{base_domain}. Nécessite un enregistrement DNS générique (*.{base_domain}) pointant vers ce serveur. Laissez vide pour désactiver le routage par sous-domaine.','Debug logging'=>'Journalisation de débogage','Writes raw diagnostic dumps of the email intake pipeline (message structure, attachment MIME detection, media conversion, post creation) to a dedicated debug directory — far more detail than the Logs tab keeps, for tracing exactly where a submission was rejected or lost. Turn off once you have what you need; files can accumulate quickly. Can also be forced from wp-config.php with `define( \'AGNOSIS_DEBUG\', true );`, which overrides this toggle. See the Debug Files panel below for the directory location and a clear-files button.'=>'Écrit des dumps de diagnostic bruts du pipeline de réception des e-mails (structure du message, détection MIME des pièces jointes, conversion des médias, création des publications) dans un répertoire de débogage dédié — bien plus détaillé que l’onglet Journaux, pour retracer précisément où une soumission a été rejetée ou perdue. Désactivez une fois que vous avez ce qu’il vous faut ; les fichiers peuvent s’accumuler rapidement. Peut aussi être forcé depuis wp-config.php avec `define( \'AGNOSIS_DEBUG\', true );`, ce qui remplace ce réglage. Voir le panneau Fichiers de débogage ci-dessous pour l’emplacement du répertoire et un bouton d’effacement des fichiers.','Debug file retention (days)'=>'Rétention des fichiers de débogage (jours)','Debug dumps older than this are permanently deleted by the daily cleanup — automatically, whether or not debug logging is currently turned on, so files left over from a past debug session don\'t linger indefinitely. A dump is a full raw copy of an artist\'s email, so this defaults shorter than the inbox/queue retention above. Default: 14 days.'=>'Les dumps de débogage plus anciens que cette durée sont supprimés définitivement lors du nettoyage quotidien — automatiquement, que la journalisation de débogage soit activée ou non, afin que les fichiers laissés d’une ancienne session de débogage ne restent pas indéfiniment. Un dump est une copie brute complète de l’e-mail d’un artiste ; la valeur par défaut est donc plus courte que la rétention de la boîte de réception / de la file d’attente ci-dessus. Valeur par défaut : 14 jours.','Email logo'=>'Logo de l’e-mail','Shown in the header of outgoing HTML emails (submission review, removal confirmation, rejection notice, and both newsletters) in place of the plain "✦ Site Name" text. Leave empty to keep the text wordmark. Displayed at up to 40px tall — any width or aspect ratio works.'=>'Affiché dans l’en-tête des e-mails HTML sortants (examen de soumission, confirmation de suppression, avis de rejet et les deux newsletters) à la place du simple texte « ✦ Nom du site ». Laissez vide pour conserver le mot-symbole textuel. Affiché jusqu’à 40 px de hauteur — toute largeur ou tout format convient.','Preset biography title'=>'Titre de biographie prédéfini','When set, every artist\'s biography page uses this exact title instead of their own, regardless of what the artist submitted, edited on their approve form, or later changed on their published page. Leave blank to keep using each artist\'s own title (the default). Shown exactly as typed here on every language version of a biography page — not machine-translated per language. See "Include artist\'s name in preset title" below.'=>'Lorsqu’il est défini, chaque page de biographie d’artiste utilise exactement ce titre à la place du sien, indépendamment de ce que l’artiste a soumis, modifié dans son formulaire d’approbation, ou changé ultérieurement sur sa page publiée. Laissez vide pour continuer à utiliser le propre titre de chaque artiste (par défaut). Affiché exactement tel qu’il est saisi ici sur chaque version linguistique d’une page de biographie — sans traduction automatique par langue. Voir « Inclure le nom de l’artiste dans le titre prédéfini » ci-dessous.','Include artist\'s name in preset title'=>'Inclure le nom de l’artiste dans le titre prédéfini','When the preset title above is set, append the artist\'s own WordPress display name to it (e.g. "Meet the Artist — Jane Doe"). Has no effect while the preset title is blank.'=>'Lorsque le titre prédéfini ci-dessus est défini, ajoute le nom d’affichage WordPress de l’artiste à la fin (par ex. « Rencontrer l’artiste — Jane Doe »). Sans effet tant que le titre prédéfini est vide.','Cloudflare Turnstile site key'=>'Clé de site Cloudflare Turnstile','From your Cloudflare Turnstile widget (dash.cloudflare.com → Turnstile). Adds a human-verification check to the public Subscribe (newsletter-signup) and Join forms. Leave either key blank to leave both forms exactly as they are today.'=>'Depuis votre widget Cloudflare Turnstile (dash.cloudflare.com → Turnstile). Ajoute une vérification humaine aux formulaires publics S’abonner (newsletter-signup) et Rejoindre. Laissez l’une ou l’autre clé vide pour laisser les deux formulaires exactement tels qu’ils sont aujourd’hui.','Cloudflare Turnstile secret key'=>'Clé secrète Cloudflare Turnstile','Kept server-side only — used to verify each form submission directly with Cloudflare before it is accepted.'=>'Conservée côté serveur uniquement — utilisée pour vérifier chaque envoi de formulaire directement auprès de Cloudflare avant qu’il ne soit accepté.','Email driver'=>'Pilote d’e-mail','Artwork submissions address'=>'Adresse de soumission des œuvres','Artists send artwork to this address — e.g. submit@agnosis.art'=>'Les artistes envoient leurs œuvres à cette adresse — par ex. submit@agnosis.art','Biography submissions address'=>'Adresse de soumission des biographies','Artists send biography updates to this address — e.g. bio@agnosis.art'=>'Les artistes envoient leurs mises à jour de biographie à cette adresse — par ex. bio@agnosis.art','Event submissions address'=>'Adresse de soumission des événements','Artists send event announcements to this address — e.g. event@agnosis.art'=>'Les artistes envoient leurs annonces d’événements à cette adresse — par ex. event@agnosis.art','Replace artwork address'=>'Remplacer l’adresse d’œuvre','Artist sends a new version of an existing artwork. Subject must match the original title. Bypasses duplicate detection — e.g. replace@agnosis.art'=>'L’artiste envoie une nouvelle version d’une œuvre existante. L’objet doit correspondre au titre d’origine. Contourne la détection des doublons — par ex. replace@agnosis.art','Removal request address'=>'Adresse de demande de suppression','Artist requests takedown of an existing artwork. Subject must match the title. Moves the post to draft pending admin review — e.g. remove@agnosis.art'=>'L’artiste demande le retrait d’une œuvre existante. L’objet doit correspondre au titre. Déplace l’article en brouillon en attente de l’examen par un administrateur — par ex. remove@agnosis.art','Promote artwork address'=>'Adresse de mise en avant d’une œuvre','Artist sends an email here (subject = exact artwork title) to choose which artwork represents them in the shared community gallery on the main site — not their own subdomain, which already shows everything they\'ve published. Any previously featured artwork is automatically demoted — e.g. promote@agnosis.art'=>'L’artiste envoie un e-mail ici (objet = titre exact de l’œuvre) pour choisir quelle œuvre le représente dans la galerie communautaire partagée sur le site principal — pas son propre sous-domaine, qui affiche déjà tout ce qu’il a publié. Toute œuvre précédemment mise en avant est automatiquement rétrogradée — par ex. promote@agnosis.art','Photo-only address'=>'Adresse pour photos uniquement','Opt-out lane for photographers and lens-based artists whose photograph is the artwork, not a snapshot of it. Submissions here are published with the original image exactly as sent — AI enhancement is skipped and the quality-rejection gate is bypassed. AI description (title, tags, alt text) still runs. Use the [Photo] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. photo@agnosis.art'=>'Voie de désactivation pour les photographes et les artistes travaillant à partir de l’image, lorsque la photographie elle-même est l’œuvre, et non une simple capture de celle-ci. Les envois reçus ici sont publiés avec l’image d’origine exactement telle qu’elle est envoyée — l’amélioration par IA est ignorée et la vérification de rejet pour qualité est contournée. La description par IA (titre, tags, texte alternatif) s’exécute tout de même. Utilisez l’indicateur d’objet [Photo] en solution de repli pour les clients de messagerie qui ne prennent pas en charge les alias dans le champ À: — par ex. photo@agnosis.art','Pure address (no AI at all)'=>'Adresse pure (sans IA du tout)','Strictest opt-out lane: nothing sent here is touched by AI — no enhancement, no vision description, no rewriting. The published post title, body, and translated-title subtitle are taken verbatim from the artist\'s own subject and message text; the attached file(s) are published exactly as sent. The quality-rejection gate is bypassed, same as Photo-only. Use the [Pure] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. pure@agnosis.art'=>'Voie de désactivation la plus stricte : rien de ce qui est envoyé ici n’est touché par l’IA — ni amélioration, ni description visuelle, ni réécriture. Le titre de l’article publié, le corps et le sous-titre du titre traduit sont repris tels quels à partir de l’objet et du texte du message de l’artiste ; les fichiers joints sont publiés exactement tels qu’ils sont envoyés. La vérification de rejet pour qualité est contournée, comme pour la voie Photos uniquement. Utilisez l’indicateur d’objet [Pure] en solution de repli pour les clients de messagerie qui ne prennent pas en charge les alias dans le champ À: — par ex. pure@agnosis.art','Goodbye / self-removal address'=>'Adresse d’adieu / suppression de soi-même','Artist emails here (any subject, no attachment needed) to request account deletion. A confirmation link is emailed back before anything is deleted — e.g. goodbye@agnosis.art'=>'L’artiste envoie un e-mail ici (objet quelconque, aucune pièce jointe requise) pour demander la suppression de son compte. Un lien de confirmation est renvoyé par e-mail avant toute suppression — par ex. goodbye@agnosis.art','Community announcement address'=>'Adresse d’annonce communautaire','Any active artist emails here (any subject, no attachment needed) to send a message to every other community member — e.g. community@agnosis.art. Never processed as a submission and never becomes a post: each recipient gets the subject and message translated into their own language, with the sender\'s name and email included so they can reply directly. Sent from the address configured under Settings → Community → Rules, which can be different from this one. Only works for a message sent by an active, admitted artist.'=>'Tout artiste actif envoie un e-mail ici (objet quelconque, aucune pièce jointe requise) pour envoyer un message à tous les autres membres de la communauté — par ex. community@agnosis.art. Jamais traité comme une soumission et ne devient jamais un article : chaque destinataire reçoit l’objet et le message traduits dans sa propre langue, avec le nom et l’e-mail de l’expéditeur afin qu’il puisse répondre directement. Envoyé depuis l’adresse configurée dans Paramètres → Communauté → Règles, qui peut être différente de celle-ci. Fonctionne uniquement pour un message envoyé par un artiste actif et admis.','IMAP host'=>'Hôte IMAP','e.g. imap.yourhost.com'=>'p. ex. imap.votrehote.com','IMAP port'=>'Port IMAP','Use SSL'=>'Utiliser SSL','Skip SSL certificate validation'=>'Ignorer la validation du certificat SSL','⚠ Use only as a temporary workaround when your mail server\'s certificate is not yet trusted (e.g. Plesk self-signed cert before Let\'s Encrypt is applied to the mail daemon). Disable this once the mail server presents a valid certificate.'=>'⚠ À utiliser uniquement comme solution temporaire lorsque le certificat de votre serveur de messagerie n’est pas encore approuvé (par ex. certificat auto-signé Plesk avant l’application de Let’s Encrypt au démon de messagerie). Désactivez cette option une fois que le serveur de messagerie présente un certificat valide.','IMAP username'=>'Nom d’utilisateur IMAP','Login username for the IMAP account — typically the catch-all mailbox address.'=>'Nom d’utilisateur de connexion pour le compte IMAP — généralement l’adresse de la boîte aux lettres générique.','Submission email password'=>'Mot de passe de l’e-mail de soumission','Webhook secret'=>'Secret du webhook','HMAC secret shared with your webhook provider (Mailgun, SendGrid…). Used for both the inbound-mail endpoint (/wp-json/agnosis/v1/email/inbound) and the bounce/complaint events endpoint (/wp-json/agnosis/v1/email/events) — point your provider\'s bounce/spam-complaint webhook at the latter to keep your subscriber and artist addresses clean.'=>'Secret HMAC partagé avec votre fournisseur de webhooks (Mailgun, SendGrid…). Utilisé à la fois pour le point de terminaison des e-mails entrants (/wp-json/agnosis/v1/email/inbound) et pour le point de terminaison des événements de rebond / plainte (/wp-json/agnosis/v1/email/events) — pointez le webhook de rebond/plainte spam de votre fournisseur vers ce dernier afin de garder propres vos adresses d’abonnés et d’artistes.','Inbox retention (days)'=>'Rétention de la boîte de réception (jours)','Seen IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup. Default: 7 days.'=>'Les messages IMAP vus et les lignes de file d’attente traitées/échouées plus anciens que cette valeur sont supprimés définitivement par le nettoyage quotidien. Par défaut : 7 jours.','Contact message retention (days)'=>'Rétention des messages de contact (jours)','Visitor-to-artist contact messages (sent or rejected) older than this are permanently deleted by the daily cleanup. The visitor\'s IP address is cleared independently after 30 days regardless of this setting, once it\'s no longer useful for abuse investigation. Default: 90 days.'=>'Les messages de contact visiteur-vers-artiste (envoyés ou rejetés) plus anciens que cette valeur sont supprimés définitivement par le nettoyage quotidien. L’adresse IP du visiteur est effacée indépendamment après 30 jours, quelle que soit cette option, dès qu’elle n’est plus utile à l’enquête sur les abus. Par défaut : 90 jours.','Per-sender hourly submission limit'=>'Limite horaire de soumissions par expéditeur','Maximum submissions accepted from a single artist per hour, across both IMAP and webhook intake. Exceeding this limit silently drops the message (no retry from ESPs). Default: 5.'=>'Nombre maximal de soumissions acceptées d’un même artiste par heure, via l’ingestion IMAP et webhook confondus. Le dépassement de cette limite rejette le message silencieusement (aucune nouvelle tentative de la part des ESP). Par défaut : 5.','Per-artist contact limit'=>'Limite de contact par artiste','Maximum messages the same visitor (by email address) can send to a single artist within the window below — applies across every language version of that artist\'s page. Default: 2.'=>'Nombre maximal de messages que le même visiteur (par adresse e-mail) peut envoyer à un même artiste dans la fenêtre ci-dessous — s’applique à toutes les versions linguistiques de la page de cet artiste. Par défaut : 2.','Per-artist contact limit window (hours)'=>'Fenêtre de la limite de contact par artiste (heures)','Time window, in hours, the per-artist contact limit above applies over. Also controls how long a visitor sees the "already contacted" notice instead of the form after messaging an artist. Default: 1 (one hour).'=>'Fenêtre de temps, en heures, sur laquelle s’applique la limite de contact par artiste ci-dessus. Contrôle aussi la durée pendant laquelle un visiteur voit l’avis « déjà contacté » à la place du formulaire après avoir écrit à un artiste. Par défaut : 1 (une heure).','Require SPF/DKIM authentication'=>'Exiger l’authentification SPF/DKIM','When enabled, intake messages must pass SPF or DKIM authentication (via the Authentication-Results header). Prevents spoofed From: addresses. Requires your ESP to include Authentication-Results headers and your domain to have SPF/DKIM records configured. Leave off if you are not sure — rejected legitimate mail is silent. Default: off.'=>'Lorsqu’elle est activée, les messages entrants doivent réussir l’authentification SPF ou DKIM (via l’en-tête Authentication-Results). Empêche l’usurpation des adresses From:. Nécessite que votre ESP inclue les en-têtes Authentication-Results et que des enregistrements SPF/DKIM soient configurés pour votre domaine. Laissez désactivé si vous n’êtes pas sûr — le rejet des e-mails légitimes est silencieux. Par défaut : désactivé.','Description provider'=>'Fournisseur de description','Analyzes the artwork image and writes the title, body, tags and alt text. WordPress AI Services delegates to whichever provider the site has configured via the AI Services plugin.'=>'Analyse l’image de l’œuvre et rédige le titre, le corps, les tags et le texte alternatif. WordPress AI Services délègue au fournisseur configuré sur le site via l’extension AI Services.','OpenAI vision model'=>'Modèle de vision OpenAI','Model used for artwork description when OpenAI is the description provider. Must support vision input.'=>'Modèle utilisé pour la description de l’œuvre lorsque OpenAI est le fournisseur de description. Doit prendre en charge l’entrée visuelle.','Anthropic model'=>'Modèle Anthropic','Model used for artwork description when Anthropic is the description provider. Must support vision input.'=>'Modèle utilisé pour la description de l’œuvre lorsque Anthropic est le fournisseur de descriptions. Doit prendre en charge une entrée visuelle.','Vision image max width (px)'=>'Largeur maximale de l’image de vision (px)','Images are downscaled proportionally to this width before being sent to the AI for description — vision token cost scales with resolution, and a description task needs far fewer pixels than the original photo. Applies to artwork photo uploads, rasterised PDF pages, and video poster frames alike. Set to 0 to always send full-resolution images (uses more tokens, no quality difference for typical description tasks). Requires the Imagick PHP extension; images are sent at their original size regardless of this setting when it is unavailable. Default: 800.'=>'Les images sont réduites proportionnellement à cette largeur avant d’être envoyées à l’IA pour description — le coût en jetons de vision augmente avec la résolution, et une tâche de description nécessite bien moins de pixels que la photo originale. S’applique de la même manière aux téléversements de photos d’œuvres, aux pages PDF rasterisées et aux images d’aperçu de vidéos. Définissez à 0 pour toujours envoyer des images en pleine résolution (utilise plus de jetons, sans différence de qualité pour les tâches de description typiques). Nécessite l’extension PHP Imagick ; les images sont envoyées à leur taille d’origine, quel que soit ce paramètre, lorsqu’elle n’est pas disponible. Par défaut : 800.','Enhancement provider'=>'Fournisseur d’amélioration','Auto (OpenAI if key is set)'=>'Automatique (OpenAI si la clé est définie)','Disabled — use original image'=>'Désactivé — utiliser l’image d’origine','Enhances the artwork image before publishing. Uses OpenAI gpt-image-1. Set to Disabled to skip enhancement and publish the original.'=>'Améliore l’image de l’œuvre avant publication. Utilise OpenAI gpt-image-1. Définissez sur Désactivé pour ignorer l’amélioration et publier l’original.','OpenAI image model'=>'Modèle d’image OpenAI','Model used for image enhancement when OpenAI is the enhancement provider.'=>'Modèle utilisé pour l’amélioration d’image lorsque OpenAI est le fournisseur d’amélioration.','Polish biography with AI'=>'Biographie polie avec l’IA','When enabled, biography submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'Lorsque cette option est activée, les soumissions de biographies sont traitées par l’IA afin de corriger l’orthographe et d’apporter de légères améliorations textuelles avant l’enregistrement.','Polish events with AI'=>'Polir les événements avec l’IA','When enabled, event submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'Lorsque cette option est activée, les soumissions d’événements sont traitées par l’IA afin de corriger l’orthographe et d’apporter de légères améliorations textuelles avant l’enregistrement.','Merge biography updates with AI'=>'Fusionner les mises à jour de biographie avec l’IA','When enabled, biography updates are merged with the existing biography using AI — new information is integrated rather than replacing everything. Recommended: artists can send incremental updates ("I just won an award") without resubmitting their full bio. Disable to always replace the biography with the latest submission.'=>'Lorsque cette option est activée, les mises à jour de biographie sont fusionnées avec la biographie existante à l’aide de l’IA — les nouvelles informations sont intégrées plutôt que de tout remplacer. Recommandé : les artistes peuvent envoyer des mises à jour incrémentales (« Je viens de gagner un prix ») sans renvoyer leur biographie complète. Désactivez pour toujours remplacer la biographie par la dernière soumission.','Rejection threshold (quality score)'=>'Seuil de rejet (score de qualité)','Photos scoring at or below this value (1–10) are automatically rejected — the artist receives a friendly email explaining the issue and is invited to resubmit. Score 0 disables automatic rejection. Must be lower than the enhancement threshold. Default: 3.'=>'Les photos ayant un score inférieur ou égal à cette valeur (1–10) sont automatiquement rejetées — l’artiste reçoit un e-mail amical expliquant le problème et est invité à soumettre à nouveau. Un score de 0 désactive le rejet automatique. Doit être inférieur au seuil d’amélioration. Valeur par défaut : 3.','Enhancement threshold (quality score)'=>'Seuil d’amélioration (score de qualité)','Photos scoring below this value (1–10) are automatically enhanced. Score 10 = perfect photograph, 1 = technically unusable. Default: 7 — only visibly problematic photos are processed. Set to 1 to disable automatic enhancement entirely.'=>'Les photos ayant un score inférieur à cette valeur (1–10) sont automatiquement améliorées. Score 10 = photographie parfaite, 1 = techniquement inutilisable. Valeur par défaut : 7 — seules les photos visiblement problématiques sont traitées. Réglez sur 1 pour désactiver entièrement l’amélioration automatique.','OpenAI API key'=>'Clé API OpenAI','Required when OpenAI is the description or enhancement provider.'=>'Requise lorsque OpenAI est le fournisseur de description ou d’amélioration.','Anthropic API key'=>'Clé API Anthropic','Required when Anthropic is the description provider.'=>'Requise lorsque Anthropic est le fournisseur de description.','Artwork display width (px)'=>'Largeur d’affichage de l’œuvre (px)','Width of the agnosis-artwork image size used in post content and lightbox. Height scales proportionally. Default: 1920. Existing images need to be regenerated after changing this value.'=>'Largeur de la taille d’image agnosis-artwork utilisée dans le contenu des publications et la lightbox. La hauteur s’adapte proportionnellement. Valeur par défaut : 1920. Les images existantes doivent être régénérées après modification de cette valeur.','Thumbnail size (px)'=>'Taille de la miniature (px)','Side length of the square agnosis-thumb size used in submission cards and dashboard. Default: 512. Existing images need to be regenerated after changing this value.'=>'Longueur du côté de la taille carrée agnosis-thumb utilisée dans les cartes de soumission et le tableau de bord. Valeur par défaut : 512. Les images existantes doivent être régénérées après modification de cette valeur.','Email image width (px)'=>'Largeur de l’image d’e-mail (px)','Width of the agnosis-email size used in artist notification emails. Height scales proportionally — no cropping. Default: 420. Existing images need to be regenerated after changing this value.'=>'Largeur de la taille agnosis-email utilisée dans les e-mails de notification aux artistes. La hauteur s’adapte proportionnellement — sans recadrage. Valeur par défaut : 420. Les images existantes doivent être régénérées après modification de cette valeur.','Gallery overview — items per page'=>'Aperçu de la galerie — éléments par page','How many artwork cards the gallery overview shows per page. Pool is built proportionally across all artists; featured artworks are preferred. Default: 12.'=>'Nombre de cartes d’œuvres que l’aperçu de la galerie affiche par page. Le pool est constitué proportionnellement à travers tous les artistes ; les œuvres mises en avant sont privilégiées. Valeur par défaut : 12.','Review link expiry (days)'=>'Expiration du lien de révision (jours)','How long the Approve & Publish / Discard links in a submission review email stay valid before an artist has to log in to manage the item instead. Applies uniformly to artwork, biography, and event drafts. Default: 7.'=>'Durée de validité des liens Approuver et publier / Rejeter dans un e-mail de révision de soumission avant qu’un artiste doive se connecter pour gérer l’élément à la place. S’applique uniformément aux brouillons d’œuvres, de biographies et d’événements. Valeur par défaut : 7.','System prompt'=>'Prompt système','Sent to the AI as the system instruction. Use {tag_count} and {excerpt_words} as tokens — they are replaced with the values below.'=>'Envoyé à l’IA comme instruction système. Utilisez {tag_count} et {excerpt_words} comme jetons — ils sont remplacés par les valeurs ci-dessous.','Artist prompt template'=>'Modèle de prompt artiste','User message sent alongside the artwork image. Use {artist_prompt} where the artist\'s own description should appear.'=>'Message utilisateur envoyé avec l’image de l’œuvre. Utilisez {artist_prompt} à l’endroit où la propre description de l’artiste doit apparaître.','Enhancement instructions'=>'Instructions d’amélioration','Instructions passed to the image enhancement provider. The AI-generated artwork description is appended automatically as context.'=>'Instructions transmises au fournisseur d’amélioration d’image. La description générée par l’IA de l’œuvre est automatiquement ajoutée comme contexte.','Number of tags'=>'Nombre de tags','How many tags the AI should generate per artwork. Referenced as {tag_count} in the system prompt.'=>'Nombre de tags que l’IA doit générer par œuvre. Référencé comme {tag_count} dans le prompt système.','Excerpt word limit'=>'Limite de mots de l’extrait','Maximum words for the one-sentence excerpt. Referenced as {excerpt_words} in the system prompt.'=>'Nombre maximal de mots pour l’extrait en une phrase. Référencé comme {excerpt_words} dans le prompt système.','Trust all admitted artists (skip link review entirely)'=>'Faire confiance à tous les artistes admis (ignorer entièrement la révision des liens)','Every artist here was already vouched in by the community — if that trust is enough for you, turn this on to embed any link an artist submits, immediately, with no allowlist check and no AI review at all (the settings below are skipped entirely while this is on). Off by default. Only enable this if you are comfortable that a bad actor who made it through admission could embed a link to anything.'=>'Chaque artiste ici a déjà été recommandé par la communauté — si cette confiance vous suffit, activez cette option pour intégrer immédiatement tout lien soumis par un artiste, sans vérification de liste d’autorisation ni aucune révision par l’IA (les réglages ci-dessous sont entièrement ignorés tant que cette option est activée). Désactivé par défaut. N’activez cette option que si vous êtes à l’aise avec l’idée qu’un mauvais acteur ayant réussi l’admission puisse intégrer un lien vers n’importe quoi.','Trusted embed platforms'=>'Plateformes d’intégration de confiance','One hostname per line. A submitted link becomes a rich embed immediately if it matches one of these (or a subdomain of one) — no AI review needed, no network request made to the link itself.'=>'Un nom d’hôte par ligne. Un lien soumis devient immédiatement une intégration enrichie s’il correspond à l’un de ceux-ci (ou à un sous-domaine de l’un d’eux) — aucune révision par l’IA n’est nécessaire, et aucune requête réseau n’est faite vers le lien lui-même.','Let artists submit other links too (AI-reviewed)'=>'Permettre aussi aux artistes de soumettre d’autres liens (révisés par l’IA)','When enabled, a link to a site not on the trusted list above is not simply discarded: the destination page is fetched and reviewed by your configured AI provider (Settings → AI Providers) against the categories below before deciding whether to embed it. If the AI cannot be reached, the request times out, or the page cannot be safely fetched, the link is not embedded — it fails safe. When disabled (the default), only the trusted platforms above are ever embedded.'=>'Lorsqu’elle est activée, un lien vers un site ne figurant pas dans la liste de confiance ci-dessus n’est pas simplement ignoré : la page de destination est récupérée et examinée par votre fournisseur d’IA configuré (Paramètres → Fournisseurs d’IA) selon les catégories ci-dessous avant de décider s’il faut l’intégrer. Si l’IA est inaccessible, si la requête expire ou si la page ne peut pas être récupérée en toute sécurité, le lien n’est pas intégré — il échoue de manière sûre. Lorsqu’elle est désactivée (par défaut), seules les plateformes de confiance ci-dessus sont intégrées.','Block pornographic / sexually explicit content'=>'Bloquer le contenu pornographique / sexuellement explicite','Only takes effect when AI review (above) is enabled.'=>'N’a d’effet que lorsque la révision par l’IA (ci-dessus) est activée.','Block primarily commercial / promotional sites'=>'Bloquer les sites principalement commerciaux / promotionnels','Online stores, advertising, marketing landing pages. Off by default — an artist linking to a shop selling their own prints is common and not inherently unwanted. Only takes effect when AI review (above) is enabled.'=>'Boutiques en ligne, publicités, pages d’atterrissage marketing. Désactivé par défaut — qu’un artiste renvoie vers une boutique vendant ses propres tirages est courant et n’est pas intrinsèquement indésirable. N’a d’effet que lorsque la révision par l’IA (ci-dessus) est activée.','Block gambling / betting sites'=>'Bloquer les sites de jeu / paris','Additional disallowed categories'=>'Catégories supplémentaires interdites','Optional — describe any other kind of content the AI should reject, in plain language (e.g. "hate speech or violent extremist content", "phishing or scam pages"). Only takes effect when AI review (above) is enabled.'=>'Facultatif — décrivez en langage simple tout autre type de contenu que l’IA doit rejeter (par ex. « discours haineux ou contenu extrémiste violent », « pages d’hameçonnage ou d’arnaque »). N’a d’effet que lorsque la révision par l’IA (ci-dessus) est activée.','Node label'=>'Libellé du nœud','How this node introduces itself to the network.'=>'La manière dont ce nœud se présente au réseau.','Enable ActivityPub federation'=>'Activer la fédération ActivityPub','Broadcast new artworks to Mastodon, Pixelfed and the Fediverse.'=>'Diffuser les nouvelles œuvres sur Mastodon, Pixelfed et le Fediverse.','Node public key'=>'Clé publique du nœud','Auto-generated RSA public key for this node. Share this with peer nodes.'=>'Clé publique RSA auto-générée pour ce nœud. Partagez-la avec les nœuds pairs.','Sender name'=>'Nom de l’expéditeur','Name shown as the sender of admission, vote, welcome, departure, and other workflow emails. Leave blank to use the site name.'=>'Nom affiché comme expéditeur des e-mails d’admission, de vote, de bienvenue, de départ et des autres e-mails de workflow. Laissez vide pour utiliser le nom du site.','Sender email address'=>'Adresse e-mail de l’expéditeur','Dedicated From: address for admission, vote, welcome, departure, invitation, and submission-review emails — e.g. hello@agnosis.art. Deliberately separate from the Settings → Newsletter sender: these are one-off actions (a vote link, a review link), not digest mail. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'Adresse « De : » dédiée pour les e-mails d’admission, de vote, de bienvenue, de départ, d’invitation et de relecture de soumission — par ex. hello@agnosis.art. Séparée volontairement de l’expéditeur des newsletters dans Paramètres → Newsletter : ce sont des actions ponctuelles (un lien de vote, un lien de relecture), et non des e-mails de synthèse. Laissez vide pour utiliser l’adresse e-mail de l’administrateur. Doit être une adresse valide et délivrable sur votre domaine (SPF/DKIM configurés), sinon les messages peuvent être marqués comme spam.','Self-removal (goodbye) requests per sender per day'=>'Demandes de suppression (au revoir) par expéditeur et par jour','Maximum number of self-removal ("goodbye") confirmation emails a single sender address can trigger per day. A genuine self-removal only ever needs to be requested once — this caps how many confirmation emails a spoofed or repeated From can be used to spam a real artist with. Default: 3.'=>'Nombre maximal d’e-mails de confirmation de suppression (« au revoir ») qu’une seule adresse d’expéditeur peut déclencher par jour. Une vraie suppression n’a besoin d’être demandée qu’une seule fois — cela limite le nombre d’e-mails de confirmation qu’un From usurpé ou répété peut utiliser pour spammer un véritable artiste. Par défaut : 3.','Community broadcasts per artist per day'=>'Diffusions à la communauté par artiste et par jour','Maximum number of messages a single artist can send to the Community announcement address (Settings → Email) per day. Prevents one member from flooding every other member\'s inbox. Default: 3.'=>'Nombre maximal de messages qu’un seul artiste peut envoyer par jour à l’adresse d’annonce de la communauté (Paramètres → E-mail). Empêche un membre d’inonder la boîte de réception de tous les autres membres. Par défaut : 3.','Community broadcast max length (characters)'=>'Longueur maximale des diffusions à la communauté (caractères)','Longer messages to the Community announcement address are bounced back to the sender instead of being broadcast — the sender is told to shorten it and resend. Measured in characters, not words, so it applies fairly across languages that don\'t use spaces between words (Chinese, Japanese, Thai, etc.). Every recipient\'s copy is translated individually, so this also caps how much a single message can cost in AI translation calls. Default: 2000. Hard maximum: 20000, regardless of this setting.'=>'Les messages plus longs envoyés à l’adresse d’annonce de la communauté sont renvoyés à l’expéditeur au lieu d’être diffusés — l’expéditeur est invité à le raccourcir puis à le renvoyer. Mesuré en caractères, et non en mots, afin de s’appliquer équitablement aux langues qui n’utilisent pas d’espaces entre les mots (chinois, japonais, thaï, etc.). La copie de chaque destinataire est traduite individuellement, ce qui limite aussi le coût qu’un seul message peut représenter en appels de traduction IA. Par défaut : 2000. Maximum absolu : 20000, indépendamment de ce réglage.','Admission vote threshold (%)'=>'Seuil de vote pour l’admission (%)','Percentage of active artists that must vote yes for admission. Combined with the minimum floor below.'=>'Pourcentage d’artistes actifs qui doivent voter oui pour l’admission. Combiné avec le minimum ci-dessous.','Admission minimum votes'=>'Minimum de votes pour l’admission','Absolute minimum positive votes required regardless of the percentage above.'=>'Nombre minimum absolu de votes positifs requis, quel que soit le pourcentage ci-dessus.','Voting window (days)'=>'Période de vote (jours)','Days an application stays open. If the threshold is not reached within this window the application is rejected.'=>'Nombre de jours pendant lesquels une candidature reste ouverte. Si le seuil n’est pas atteint dans cette période, la candidature est rejetée.','Resolved application retention (days)'=>'Conservation des candidatures résolues (jours)','A rejected, withdrawn, or left application\'s email, name, biography, statement, and portfolio link are anonymized by the daily cleanup after this many days — the application record itself (status and dates) is kept for admission history. A banned artist\'s biography/statement/portfolio are anonymized on the same schedule, but their email is deliberately kept so the ban stays enforceable. Default: 180 days.'=>'L’e-mail, le nom, la biographie, la déclaration et le lien de portfolio d’une candidature rejetée, retirée ou abandonnée sont anonymisés par le nettoyage quotidien après ce nombre de jours — l’enregistrement de la candidature lui-même (statut et dates) est conservé pour l’historique d’admission. La biographie, la déclaration et le portfolio d’un artiste banni sont anonymisés selon le même calendrier, mais son e-mail est volontairement conservé afin que l’interdiction reste applicable. Par défaut : 180 jours.','After applying, send artists to'=>'Après la candidature, rediriger les artistes vers','Optional — pick a page explaining the vouching process and what happens next. When the application is submitted successfully, the artist is redirected there instead of just seeing an inline confirmation message. Leave as "None" to keep the inline message only.'=>'Facultatif — choisissez une page expliquant le processus de parrainage et la suite. Lorsque la candidature est soumise avec succès, l’artiste y est redirigé au lieu de voir simplement un message de confirmation intégré. Laissez sur « Aucun » pour conserver uniquement le message intégré.','Community size cap'=>'Capacité maximale de la communauté','Maximum number of admitted artists. When full, new applications join a waitlist instead of being rejected, and a freed slot admits the next in line. Set to 0 for no cap. The community can also vote to change this.'=>'Nombre maximal d’artistes admis. Lorsque la communauté est pleine, les nouvelles candidatures rejoignent une liste d’attente au lieu d’être rejetées, et une place libérée admet la personne suivante dans la file. Réglez sur 0 pour ne pas fixer de limite. La communauté peut aussi voter pour modifier ce réglage.','Cap-change co-signers required'=>'Co-signataires requis pour changer la capacité','How many artists must co-sign a proposal to change the community size cap before it opens as a full community vote.'=>'Nombre d’artistes qui doivent co-signer une proposition de modification de la capacité de la communauté avant qu’elle ne s’ouvre comme un vote complet de la communauté.','Cap-change vote window (days)'=>'Période de vote pour le changement de capacité (jours)','Days a community cap-change vote stays open. A strict majority of active artists voting yes adopts the new cap.'=>'Nombre de jours pendant lesquels un vote de changement de capacité de la communauté reste ouvert. Une majorité stricte des artistes actifs votant oui adopte la nouvelle capacité.','Removal nominations required'=>'Nominations requises pour la suppression','Number of artist nominations needed before a community removal vote opens. Admins can bypass this threshold.'=>'Nombre de nominations d’artistes nécessaires avant l’ouverture d’un vote communautaire de suppression. Les administrateurs peuvent contourner ce seuil.','Removal vote window (days)'=>'Période de vote pour la suppression (jours)','Days a community removal vote stays open. A majority (>50%) of active artists must vote yes for removal to proceed.'=>'Nombre de jours pendant lesquels un vote communautaire de suppression reste ouvert. Une majorité (>50 %) des artistes actifs doit voter oui pour que la suppression aboutisse.','Invitation intro'=>'Introduction de l’invitation','Agnosis is a small, self-hosted home for artists who\'d rather make work than manage a platform. There\'s no algorithm deciding who sees your art, no portfolio site to maintain, and no account to configure — just your work, published and translated automatically for a global audience.

Being part of the community is simple: Fellow artists vouch for new applicants, and everyone keeps full ownership of what they publish; you can leave at any time and take your work with you.

Once admitted, you submit new work by sending it as an email — no dashboard, no forms and you can update, promote or remove your artwork as well sending an email. You can find more information visiting the agnosis.art website.'=>'Agnosis est un petit foyer auto-hébergé pour les artistes qui préfèrent créer plutôt que gérer une plateforme. Aucun algorithme ne décide qui voit votre art, aucun site portfolio n’est à maintenir, et aucun compte n’est à configurer — juste votre travail, publié et traduit automatiquement pour un public mondial.

Faire partie de la communauté est simple : des artistes pairs parrainent les nouveaux candidats, et chacun conserve l’entière propriété de ce qu’il publie ; vous pouvez partir à tout moment et emporter votre travail avec vous.

Une fois admis, vous soumettez de nouvelles œuvres en les envoyant par e-mail — pas de tableau de bord, pas de formulaires, et vous pouvez aussi mettre à jour, promouvoir ou supprimer votre œuvre simplement en envoyant un e-mail. Vous trouverez plus d’informations sur le site agnosis.art.','Shown near the top of the "Send Invitation" email below (an "Apply to join" link and site name follow automatically — no need to add either here). Two or three short paragraphs is plenty. Standing copy, not cleared after use like the newsletter intros above — translated automatically when an invitation is sent in a language other than the site\'s own.'=>'Affiché près du haut de l’e-mail « Envoyer une invitation » ci-dessous (un lien « Demander à rejoindre » et le nom du site suivent automatiquement — pas besoin d’ajouter l’un ou l’autre ici). Deux ou trois courts paragraphes suffisent. Texte permanent, non effacé après usage comme les introductions de newsletter ci-dessus — traduit automatiquement lorsqu’une invitation est envoyée dans une langue autre que celle du site.','Transaction fee (%)'=>'Frais de transaction (%)','Percentage retained by this node on donations and art sales. Artists pay nothing up front.'=>'Pourcentage conservé par ce nœud sur les dons et les ventes d’œuvres. Les artistes ne paient rien à l’avance.','Name shown as the sender of digest emails. Leave blank to use the site name.'=>'Nom affiché comme expéditeur des e-mails de synthèse. Laissez vide pour utiliser le nom du site.','Dedicated From: address for both newsletters, e.g. newsletter@agnosis.art — keeps digest mail separate from the site\'s admin email for deliverability and so artists can filter it. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'Adresse d’expéditeur dédiée pour les deux newsletters, par ex. newsletter@agnosis.art — permet de séparer les e-mails du digest de l’adresse admin du site pour une meilleure délivrabilité, et pour que les artistes puissent les filtrer. Laissez vide pour utiliser l’adresse admin. Doit être une adresse valide et délivrable sur votre domaine (SPF/DKIM configurés), sinon les messages peuvent être marqués comme spam.','Auto-draft newsletter intros'=>'Rédaction automatique des intros de newsletter','When enabled, Agnosis drafts an intro via AI ahead of each issue (see the lead time below), saves it to that newsletter\'s intro field, and emails you to review it — unless you\'ve already written one for that cycle. Disable to leave both intro fields exactly as you left them, always.'=>'Lorsque cette option est activée, Agnosis rédige une intro via l’IA avant chaque numéro (voir le délai ci-dessous), l’enregistre dans le champ d’intro de cette newsletter et vous envoie un e-mail pour la relire — sauf si vous en avez déjà rédigé une pour ce cycle. Désactivez pour laisser les deux champs d’intro exactement tels que vous les avez laissés, en permanence.','Draft intro this many hours ahead'=>'Rédiger l’intro ce nombre d’heures à l’avance','How long before an issue is due Agnosis proposes an AI-drafted intro. Only takes effect when auto-drafting (above) is enabled. Default: 24.'=>'Temps avant l’échéance d’un numéro auquel Agnosis propose une intro rédigée par l’IA. N’a effet que lorsque la rédaction automatique (ci-dessus) est activée. Par défaut : 24.','Artist newsletter'=>'Newsletter des artistes','Admitted artists are auto-enrolled (they can unsubscribe from any issue with one click). Community digest: recent activity, new members, open votes.'=>'Les artistes admis sont inscrits automatiquement (ils peuvent se désabonner de n’importe quel numéro en un clic). Digest de la communauté : activité récente, nouveaux membres, votes ouverts.','Artist newsletter frequency (days)'=>'Fréquence de la newsletter des artistes (jours)','Default 30 ≈ monthly. A new issue is prepared once this many days have passed since the last one was sent.'=>'Par défaut 30 ≈ mensuel. Un nouveau numéro est préparé une fois que ce nombre de jours s’est écoulé depuis l’envoi du précédent.','Artist newsletter intro'=>'Intro de la newsletter des artistes','Optional note prepended to the next artist issue only — cleared automatically once that issue is queued. Leave blank to send the auto-digest with no intro. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'Note facultative préfixée uniquement à la prochaine édition artiste — effacée automatiquement une fois cette édition mise en file d’attente. Laissez vide pour envoyer le digest automatique sans introduction. Si laissé vide, Agnosis en rédige une automatiquement à partir des nouveautés environ un jour avant l’envoi de l’édition, et vous envoie un e-mail pour la relire d’abord — écrivez la vôtre ici à tout moment pour éviter cela.','Public newsletter'=>'Newsletter publique','Visitors subscribe via the agnosis/newsletter-signup block (double opt-in). Digest: new artwork and events published since the last issue.'=>'Les visiteurs s’abonnent via le bloc agnosis/newsletter-signup (double opt-in). Digest : nouvelles œuvres et événements publiés depuis la dernière édition.','Public newsletter frequency (days)'=>'Fréquence de la newsletter publique (jours)','Default 30 ≈ monthly.'=>'Par défaut 30 ≈ mensuel.','Public newsletter intro'=>'Introduction de la newsletter publique','Optional note prepended to the next public issue only — cleared automatically once that issue is queued. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'Note facultative préfixée uniquement à la prochaine édition publique — effacée automatiquement une fois cette édition mise en file d’attente. Si laissé vide, Agnosis en rédige une automatiquement à partir des nouveautés environ un jour avant l’envoi de l’édition, et vous envoie un e-mail pour la relire d’abord — écrivez la vôtre ici à tout moment pour éviter cela.','Send batch size'=>'Taille du lot d’envoi','Recipients emailed per 5-minute cron tick. Lower this if your host throttles outbound mail; raise it for faster delivery on hosts with generous limits.'=>'Nombre de destinataires envoyés à chaque tick cron de 5 minutes. Réduisez cette valeur si votre hébergeur limite les e-mails sortants ; augmentez-la pour une livraison plus rapide sur les hébergements avec des limites généreuses.','Self-hosting comfort threshold'=>'Seuil de confort pour l’auto-hébergement','Advisory only — self-hosted sending keeps working above this count. Once confirmed public subscribers pass it, this page shows a reminder to consider an email service provider (e.g. Brevo\'s free tier) instead.'=>'À titre indicatif uniquement — l’envoi en auto-hébergement continue de fonctionner au-delà de ce nombre. Une fois que les abonnés publics confirmés le dépassent, cette page affiche un rappel suggérant d’envisager plutôt un fournisseur de service e-mail (par ex. l’offre gratuite de Brevo).','Sends a minimal ping ("Reply with the word: ping") using the configured API key.'=>'Envoie un ping minimal (« Répondez avec le mot : ping ») en utilisant la clé API configurée.','Sends a minimal ping using the configured API key.'=>'Envoie un ping minimal en utilisant la clé API configurée.','WordPress AI Client'=>'Client IA WordPress','Checks that wp_ai_client_prompt() is available (WordPress 7.0+) and a text-generation model is configured.'=>'Vérifie que wp_ai_client_prompt() est disponible (WordPress 7.0+) et qu’un modèle de génération de texte est configuré.','Test AI Providers'=>'Tester les fournisseurs d’IA','Test %s'=>'Tester %s','Bot Protection'=>'Protection ضد les robots','Turnstile is configured.'=>'Turnstile est configuré.','The Join application form and the Newsletter Subscribe form both require human verification before they accept a submission.'=>'Le formulaire de candidature Join et le formulaire d’abonnement à la newsletter exigent tous deux une vérification humaine avant d’accepter une soumission.','Turnstile is not configured.'=>'Turnstile n’est pas configuré.','Your Join application form is public — anyone can submit an application, and a submitted (and confirmed) application still emails every admitted artist and admin. Right now the only thing standing between that form and an automated bot is a fixed 5-submissions-per-minute-per-IP limit, which a distributed bot can work around entirely. Add a Cloudflare Turnstile site key and secret key above to require human verification on both the Join form and the Newsletter Subscribe form.'=>'Votre formulaire de candidature Join est public — n’importe qui peut soumettre une candidature, et une candidature soumise (et confirmée) envoie quand même un e-mail à chaque artiste admis et à chaque administrateur. Pour l’instant, la seule chose qui protège ce formulaire contre un bot automatisé est une limite fixe de 5 soumissions par minute et par adresse IP, qu’un bot distribué peut contourner entièrement. Ajoutez ci-dessus une clé de site Cloudflare Turnstile et une clé secrète pour exiger une vérification humaine à la fois sur le formulaire Join et sur le formulaire d’abonnement à la newsletter.','OpenAI'=>'OpenAI','Anthropic'=>'Anthropic','AI Processing & Privacy Policy'=>'Politique de traitement et de confidentialité de l’IA','A Privacy Policy page is set.'=>'Une page de Politique de confidentialité est définie.','Suggested wording covering %s and public federation was added to it automatically — review it under Settings → Privacy → "Guide" before publishing, and check with your provider(s) about their own data processing agreement (DPA) for your compliance obligations.'=>'Une formulation suggérée couvrant %s et la fédération publique y a été ajoutée automatiquement — vérifiez-la dans Réglages → Confidentialité → « Guide » avant publication, et renseignez-vous auprès de votre ou vos fournisseurs sur leur propre accord de traitement des données (DPA) afin de respecter vos obligations de conformité.','No Privacy Policy page is set.'=>'Aucune page de Politique de confidentialité n’est définie.','Submitted artwork, text, and visitor contact messages are sent to %s for processing. Create or choose a page under Settings → Privacy — this plugin has already prepared suggested wording you\'ll find there under "Guide". You may also want to review that provider\'s data processing agreement (DPA) for your own compliance obligations.'=>'Les œuvres soumises, les textes et les messages de contact des visiteurs sont envoyés à %s pour traitement. Créez ou choisissez une page dans Réglages → Confidentialité — cette extension y a déjà préparé une formulation suggérée que vous trouverez sous « Guide ». Vous voudrez peut-être aussi examiner l’accord de traitement des données (DPA) de ce fournisseur pour vos propres obligations de conformité.','Go to Settings → Privacy'=>'Aller à Réglages → Confidentialité','Debug Files'=>'Fichiers de débogage','Currently'=>'Actuellement','Enabled'=>'Activé','Disabled'=>'Désactivé','Forced ON by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'FORCÉ SUR ON par la constante AGNOSIS_DEBUG dans wp-config.php — la case à cocher ci-dessus n’a aucun effet tant que cette ligne n’est pas supprimée.','Forced OFF by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'FORCÉ SUR OFF par la constante AGNOSIS_DEBUG dans wp-config.php — la case à cocher ci-dessus n’a aucun effet tant que cette ligne n’est pas supprimée.','Directory'=>'Répertoire','Filter with agnosis_debug_dir to redirect debug output elsewhere.'=>'Filtrez avec agnosis_debug_dir pour rediriger la sortie de débogage ailleurs.','.txt file(s) in the directory'=>'fichier(s) .txt dans le répertoire','Delete all .txt files in the debug directory? The directory itself stays in place so future debug writes still land cleanly.'=>'Supprimer tous les fichiers .txt du répertoire de débogage ? Le répertoire lui-même reste en place afin que les futures écritures de débogage s’y déposent correctement.','Clear Debug Files'=>'Effacer les fichiers de débogage','Term Translation Cache'=>'Cache de traduction des termes','Cached translations'=>'Traductions en cache','AI-translated tag/medium term names, cached so the same term always gets the same translated label instead of a fresh AI phrasing per post. Renaming a term already clears its own cached entry automatically; use the button below only if a cached translation itself is wrong.'=>'Noms de termes de tag / média traduits par IA, mis en cache afin que le même terme obtienne toujours le même libellé traduit au lieu d’une nouvelle formulation IA à chaque publication. Renommer un terme efface déjà automatiquement sa propre entrée en cache ; utilisez le bouton ci-dessous uniquement si une traduction en cache est elle-même erronée.','Clear every cached term translation? Nothing is deleted from your site — terms will simply be re-translated by AI the next time they\'re needed.'=>'Effacer toutes les traductions de termes en cache ? Rien ne sera supprimé de votre site — les termes seront simplement retraduits par l’IA la prochaine fois qu’ils seront nécessaires.','Clear Term Translation Cache'=>'Effacer le cache de traduction des termes','Pipeline Logs'=>'Journaux du pipeline','Clear all log entries?'=>'Effacer toutes les entrées du journal ?','Clear All'=>'Tout effacer','%d entries total. Logs are pruned automatically according to the Inbox retention setting.'=>'%d entrées au total. Les journaux sont purgés automatiquement selon le paramètre de rétention de la boîte de réception.','No log entries yet.'=>'Aucune entrée de journal pour le moment.','Time'=>'Heure','Level'=>'Niveau','Context'=>'Contexte','Inbox Tools'=>'Outils de boîte de réception','Test connection'=>'Tester la connexion','Test IMAP Connection'=>'Tester la connexion IMAP','Connects to the configured mailbox and reports the total and unseen message count.'=>'Se connecte à la boîte aux lettres configurée et indique le nombre total de messages et de messages non lus.','Poll inbox now'=>'Interroger la boîte de réception maintenant','Poll Inbox Now'=>'Interroger la boîte de réception maintenant','Fetches unseen messages immediately without waiting for WP-Cron. Then click "Process Pending Queue" to run the AI pipeline.'=>'Récupère immédiatement les messages non lus sans attendre WP-Cron. Cliquez ensuite sur « Traiter la file d’attente en attente » pour exécuter le pipeline IA.','Process queue'=>'Traiter la file d’attente','Process Pending Queue'=>'Traiter la file d’attente en attente','Immediately runs the AI pipeline on all pending queue items without waiting for WP-Cron. Use this to test the end-to-end flow after a poll.'=>'Exécute immédiatement le pipeline IA sur tous les éléments en attente de la file, sans attendre WP-Cron. Utilisez cela pour tester le flux de bout en bout après un sondage.','Force reprocess'=>'Forcer le retraitement','Force Reprocess Inbox'=>'Forcer le retraitement de la boîte de réception','Resets failed/stuck/orphaned queue rows back to pending, then immediately polls for unprocessed messages. Then click "Process Pending Queue" to run the AI pipeline. Already-published artworks with valid posts are never re-processed.'=>'Réinitialise les lignes de file d’attente échouées/bloquées/orphelines à l’état en attente, puis interroge immédiatement les messages non traités. Cliquez ensuite sur « Traiter la file d’attente en attente » pour exécuter le pipeline IA. Les œuvres déjà publiées avec des articles valides ne sont jamais retraitées.','Deliverability'=>'Délivrabilité','A diagnostic check only — nothing here changes how mail is sent. On ordinary hosting (PHP mail(), no SMTP plugin), mail sent from an address that doesn\'t match your site\'s own domain, or from a domain with no SPF/DMARC record at all, is increasingly likely to land in spam or be rejected outright by large mailbox providers. If any row below looks wrong, the most reliable fix is installing an SMTP-sending plugin (WP Mail SMTP, Post SMTP, FluentSMTP, and others all work) configured against a real transactional mail provider, and adding SPF/DMARC records for the domain you send from at your DNS host.'=>'Il s’agit uniquement d’un contrôle de diagnostic — rien ici ne modifie la manière dont le courrier est envoyé. Sur un hébergement standard (PHP mail(), sans plugin SMTP), les e-mails envoyés depuis une adresse qui ne correspond pas au domaine de votre site, ou depuis un domaine sans enregistrement SPF/DMARC du tout, ont de plus en plus de chances d’atterrir dans les spams ou d’être rejetés purement et simplement par les grands fournisseurs de boîtes mail. Si une des lignes ci-dessous vous semble incorrecte, la solution la plus fiable consiste à installer un plugin d’envoi SMTP (WP Mail SMTP, Post SMTP, FluentSMTP et d’autres fonctionnent), configuré avec un véritable fournisseur de messagerie transactionnelle, puis à ajouter des enregistrements SPF/DMARC pour le domaine d’envoi chez votre hébergeur DNS.','From identity'=>'Identité d’envoi','Domain matches site?'=>'Le domaine correspond-il au site ?','SPF record'=>'Enregistrement SPF','DMARC record'=>'Enregistrement DMARC','SMTP plugin'=>'Plugin SMTP','Detected: %s'=>'Détecté : %s','None of the common SMTP-sending plugins were detected — this site is likely relying on PHP\'s built-in mail(), which most hosts deliver poorly through.'=>'Aucun des plugins courants d’envoi SMTP n’a été détecté — ce site s’appuie probablement sur la fonction mail() intégrée de PHP, que la plupart des hébergeurs acheminent mal.','Send a real test email to:'=>'Envoyer un véritable e-mail de test à :','Send Test'=>'Envoyer le test','Sends one plain-text email from the same community identity used for review/vote/vouch mail. Reaching your inbox is a good sign; landing in spam or not arriving at all confirms a real deliverability problem regardless of what the checks above say.'=>'Envoie un e-mail en texte brut depuis la même identité de communauté utilisée pour les e-mails de revue/vote/soutien. S’il arrive dans votre boîte de réception, c’est bon signe ; s’il arrive en spam ou n’arrive pas du tout, cela confirme un vrai problème de délivrabilité, quels que soient les résultats des vérifications ci-dessus.','Found'=>'Trouvé','Not found'=>'Non trouvé','DNS lookup failed'=>'Échec de la recherche DNS','Unavailable on this host'=>'Indisponible sur cet hébergeur','No address configured'=>'Aucune adresse configurée','[TEST] Deliverability check from %s'=>'[TEST] Contrôle de délivrabilité depuis %s','This is a one-off deliverability test from your Agnosis Settings → Email Inbox page. If you\'re reading this in your inbox (not spam), the community/transactional From identity is deliverable to this address.'=>'Il s’agit d’un test de délivrabilité ponctuel depuis votre page Agnosis Réglages → Boîte de réception des e-mails. Si vous lisez ce message dans votre boîte de réception (et non dans les spams), l’identité d’envoi communautaire/transactionnelle est bien distribuable à cette adresse.','Pending Applications'=>'Candidatures en attente','%d application is awaiting email confirmation from the applicant and isn\'t listed below yet.'=>'%d candidature attend la confirmation par e-mail du candidat et n’est pas encore listée ci-dessous.' . "\0" . '%d candidatures attendent la confirmation par e-mail des candidats et ne sont pas encore listées ci-dessous.','No pending applications.'=>'Aucune candidature en attente.','%d positive vote(s) currently required for admission.'=>'%d vote(s) positif(s) actuellement requis pour l’admission.','Applicant'=>'Candidat','Applied'=>'Date de candidature','Votes'=>'Votes','Bio / Portfolio'=>'Bio / Portfolio','%1$d / %2$d'=>'%1$d / %2$d','Portfolio ↗'=>'Portfolio ↗','Admit'=>'Admettre','Reject'=>'Rejeter','No admitted members yet.'=>'Aucun membre admis pour le moment.','Joined'=>'Inscrit','Banned until %s'=>'Banni jusqu’au %s','Banned'=>'Banni','Active'=>'Actif','This address has bounced or been reported as spam — mail may no longer be reaching this artist.'=>'Cette adresse a rebondi ou a été signalée comme spam — les e-mails n’atteignent peut-être plus cet artiste.','⚠ %d bounce'=>'⚠ %d rebond' . "\0" . '⚠ %d rebonds','This artist has muted community broadcast messages.'=>'Cet artiste a désactivé les messages de diffusion de la communauté.','🔇 Broadcasts muted'=>'🔇 Diffusions désactivées','This artist receives one daily digest of open applications instead of an email per application.'=>'Cet artiste reçoit un digest quotidien des candidatures ouvertes au lieu d’un e-mail par candidature.','📬 Vote digest mode'=>'📬 Mode digest des votes','Leave the date blank to ban indefinitely. Continue?'=>'Laissez la date vide pour bannir indéfiniment. Continuer ?','Leave blank to ban indefinitely'=>'Laisser vide pour bannir indéfiniment','Suspend'=>'Suspendre','Permanently delete this artist and all their content? This cannot be undone.'=>'Supprimer définitivement cet artiste et tout son contenu ? Cette action est irréversible.','Open a community removal vote for this artist? All members will be emailed.'=>'Ouvrir un vote communautaire pour la suppression de cet artiste ? Tous les membres seront informés par e-mail.','Open Vote'=>'Ouvrir le vote','Newsletter Status'=>'Statut de la newsletter','You have %1$d confirmed public subscribers, above the configured comfort threshold of %2$d. Self-hosted sending still works, but you may want to connect an email service provider (e.g. Brevo\'s free tier) for better deliverability at this size.'=>'Vous avez %1$d abonnés publics confirmés, au-dessus du seuil de confort configuré de %2$d. L’envoi auto-hébergé fonctionne toujours, mais vous souhaiterez peut-être connecter un fournisseur de services e-mail (par ex. le niveau gratuit de Brevo) pour une meilleure délivrabilité à cette taille.','Audience'=>'Audience','Last sent'=>'Dernier envoi','Action'=>'Action','Failed recipients'=>'Destinataires en échec','Send a test'=>'Envoyer un test','%1$d admitted (%2$d opted out)'=>'%1$d admis (%2$d ont choisi de se désinscrire)','Sending…'=>'Envoi…','Idle'=>'Inactif','Send Now'=>'Envoyer maintenant','Public'=>'Public','%1$d confirmed, %2$d pending confirmation, %3$d unsubscribed, %4$d bounced'=>'%1$d confirmés, %2$d en attente de confirmation, %3$d désabonnés, %4$d rebondis','By language: %s'=>'Par langue : %s','Add the "Newsletter Signup" block to any page to let visitors subscribe to the public newsletter. Artists are enrolled automatically and can unsubscribe from any issue with one click.'=>'Ajoutez le bloc « Inscription à la newsletter » à n’importe quelle page pour permettre aux visiteurs de s’abonner à la newsletter publique. Les artistes sont inscrits automatiquement et peuvent se désabonner de n’importe quel numéro en un clic.','Never'=>'Jamais','Unknown'=>'Inconnu','None'=>'Aucun','%d failed'=>'%d échecs' . "\0" . '%d échecs','Retry Failed'=>'Réessayer les échecs','Invite an Artist'=>'Inviter un artiste','Send a one-off email inviting someone to apply. Nothing is tracked or scheduled — this sends immediately to the address below.'=>'Envoyez un e-mail ponctuel pour inviter quelqu’un à postuler. Rien n’est suivi ni planifié — cela envoie immédiatement à l’adresse ci-dessous.','artist@example.com'=>'artiste@exemple.com','Send Invitation'=>'Envoyer l’invitation','Permission denied.'=>'Permission refusée.','OpenAI API key not configured.'=>'Clé API OpenAI non configurée.','OpenAI connection successful.'=>'Connexion OpenAI réussie.','Anthropic API key not configured.'=>'Clé API Anthropic non configurée.','Anthropic connection successful.'=>'Connexion Anthropic réussie.','WordPress AI Client requires WordPress 7.0 or later.'=>'WordPress AI Client requiert WordPress 7.0 ou version ultérieure.','No text-generation model configured. Set one up under Settings → Connectors.'=>'Aucun modèle de génération de texte n’est configuré. Configurez-en un dans Réglages → Connecteurs.','WordPress AI Client is available and a text-generation model is configured.'=>'WordPress AI Client est disponible et un modèle de génération de texte est configuré.','Unknown provider.'=>'Fournisseur inconnu.','HTTP %d'=>'HTTP %d','The artist sent no subject line or message with this submission — let the image speak entirely for itself.'=>'L’artiste n’a envoyé ни objet ni message avec cette soumission — laissez l’image parler entièrement d’elle-même.','Name'=>'Nom','Bio'=>'Bio','Statement'=>'Déclaration','%1$s must be %2$d characters or fewer.'=>'%1$s doit comporter %2$d caractères ou moins.','Please select your language.'=>'Veuillez sélectionner votre langue.','An account with this email address already exists.'=>'Un compte avec cette adresse e-mail existe déjà.','This email address belongs to an admitted artist.'=>'Cette adresse e-mail appartient à un artiste admis.','An application for this email address is already pending.'=>'Une demande pour cette adresse e-mail est déjà en attente.','Application not found.'=>'Demande introuvable.','Only admitted artists can vouch.'=>'Seuls les artistes admis peuvent parrainer.','Admin access required.'=>'Accès administrateur requis.','You cannot vote on your own application.'=>'Vous ne pouvez pas voter sur votre propre candidature.','Invalid or incomplete link.'=>'Lien invalide ou incomplet.','This confirmation link is invalid or has already been used.'=>'Ce lien de confirmation est invalide ou a déjà été utilisé.','Confirm your application?'=>'Confirmer votre candidature ?','Your application will open for community review once you confirm below.'=>'Votre candidature sera ouverte à l’examen de la communauté une fois que vous aurez confirmé ci-dessous.','Confirm my application'=>'Confirmer ma candidature','This community is currently full, so your application has joined the waitlist — when a member leaves, the next person in line is welcomed in.'=>'Cette communauté est actuellement complète, votre candidature a donc été ajoutée à la liste d’attente — lorsqu’un membre part, la prochaine personne sur la liste est accueillie.','You\'re all set — the community can now review your application and vote.'=>'C’est bon — la communauté peut maintenant examiner votre candidature et voter.','Application confirmed'=>'Candidature confirmée','Thanks, %s!'=>'Merci, %s !','Link error'=>'Erreur de lien','Confirm your application to %s'=>'Confirmer votre candidature à %s','Your application to %s'=>'Votre candidature à %s','Application by %s has closed'=>'La candidature de %s est clôturée','Welcome to %s'=>'Bienvenue sur %s','We received your application to %s'=>'Nous avons bien reçu votre candidature à %s','Hi %s,'=>'Bonjour %s,','One last step before %s can review your application: confirm this is really your email address.'=>'Dernière étape avant que %s puisse examiner votre candidature : confirmez qu’il s’agit bien de votre adresse e-mail.','If you didn\'t apply, simply ignore this email — nothing happens until this link is clicked.'=>'Si vous n’avez pas fait de demande, ignorez simplement cet e-mail — rien ne se passe tant que ce lien n’est pas cliqué.','%s — art blooming out of oblivion'=>'%s — l’art s’épanouit hors de l’oubli','Thank you for applying to %s. Your application has been received and is now open for community review.'=>'Merci d’avoir postulé à %s. Votre candidature a bien été reçue et est maintenant ouverte à l’examen de la communauté.','The community has %d days to vote. We will let you know the outcome by email.'=>'La communauté dispose de %d jours pour voter. Nous vous informerons du résultat par e-mail.','New application: %1$s wants to join %2$s'=>'Nouvelle candidature : %1$s souhaite rejoindre %2$s','%1$s has applied to join %2$s. You have %3$d days to vote.'=>'%1$s a demandé à rejoindre %2$s. Vous avez %3$d jours pour voter.','Portfolio:'=>'Portfolio :','Vote YES'=>'Voter OUI','Vote NO'=>'Voter NON','You can change your vote at any time within the voting window.'=>'Vous pouvez modifier votre vote à tout moment pendant la période de vote.','Thank you for applying to %s. Unfortunately, your application did not receive enough votes within the voting window.'=>'Merci d’avoir postulé à %s. Malheureusement, votre candidature n’a pas reçu suffisamment de votes pendant la période de vote.','You are welcome to apply again in the future.'=>'Vous êtes invité·e à postuler de nouveau à l’avenir.','The application by %s has closed without reaching the admission threshold. No action required.'=>'La candidature de %s est clôturée sans avoir atteint le seuil d’admission. Aucune action requise.','The %s community has admitted you as an artist. Welcome!'=>'La communauté %s vous a admis en tant qu’artiste. Bienvenue !','Your gallery:'=>'Votre galerie :','Your submissions:'=>'Vos soumissions :','How to share your work — send an email to:'=>'Comment partager votre travail — envoyez un e-mail à :','Subject line conventions:'=>'Conventions de l’objet :','Artwork (default) — any subject'=>'Œuvre (par défaut) — n’importe quel sujet','[Biography] — biography update'=>'[Biographie] — mise à jour de la biographie','[Event] — event announcement'=>'[Événement] — annonce d’événement','[Photo] — publish as-is, no AI enhancement (fallback for mail apps without To: aliases)'=>'[Photo] — publier tel quel, sans amélioration par IA (solution de repli pour les clients mail sans alias Dans :)','[Pure] — publish exactly as sent, no AI at all (fallback for mail apps without To: aliases)'=>'[Pur] — publier exactement comme envoyé, sans IA du tout (solution de repli pour les clients mail sans alias Dans :)','To leave the network and delete your account:'=>'Pour quitter le réseau et supprimer votre compte :','Send any email (no attachment needed). You will receive a confirmation link — nothing is deleted until you click it.'=>'Envoyez simplement un e-mail (aucune pièce jointe nécessaire). Vous recevrez un lien de confirmation — rien ne sera supprimé avant que vous ne cliquiez dessus.','No login is needed to work with Agnosis — everything above happens by email. If you\'d also like to use the site\'s optional online features (like previewing a submission before it publishes), you can set up a password whenever you like using'=>'Aucune connexion n’est nécessaire pour utiliser Agnosis — tout ce qui précède se fait par e-mail. Si vous souhaitez aussi utiliser les fonctionnalités en ligne facultatives du site (comme prévisualiser une soumission avant sa publication), vous pouvez définir un mot de passe quand vous le souhaitez en utilisant','password recovery'=>'récupération du mot de passe','Submit artwork'=>'Soumettre une œuvre','Submit biography'=>'Soumettre une biographie','Submit event'=>'Soumettre un événement','Replace artwork (subject: exact title)'=>'Remplacer l’œuvre (objet : titre exact)','Remove artwork (subject: exact title)'=>'Supprimer l’œuvre (objet : titre exact)','Feature artwork in the shared gallery (subject: exact title)'=>'Mettre l’œuvre en avant dans la galerie partagée (objet : titre exact)','Photo-only — publish as-is, no AI enhancement'=>'Photo uniquement — publier tel quel, sans amélioration par IA','Pure — publish exactly as sent, no AI at all'=>'Pur — publier exactement comme envoyé, sans IA du tout','About %s'=>'À propos de %s','%1$s — %2$s'=>'%1$s — %2$s','[%s] Your community message was not sent — too long'=>'[%s] Votre message à la communauté n’a pas été envoyé — trop long','Hi %1$s,

Your message to the community was %2$d characters long — the current limit is %3$d. It was not sent to anyone.

Every recipient\'s copy is translated individually into their own language, so a very long message is costly to translate for the whole community. Please shorten it and send it again.

— %4$s'=>'Bonjour %1$s,

Votre message à la communauté compte %2$d caractères — la limite actuelle est de %3$d. Il n’a été envoyé à personne.

La copie de chaque destinataire est traduite individuellement dans sa propre langue, donc un message très long est coûteux à traduire pour toute la communauté. Veuillez le raccourcir et l’envoyer à nouveau.

— %4$s','[%s] Your community message was not sent — no content found'=>'[%s] Votre message à la communauté n’a pas été envoyé — aucun contenu trouvé','Hi %1$s,

Your message to the community had no subject or message text that could be found — this often happens when an email client sends an HTML-only message with no plain-text version included. It was not sent to anyone.

Please try sending it again with plain text included.

— %2$s'=>'Bonjour %1$s,

Votre message à la communauté ne contenait ni objet ni texte de message trouvable — cela arrive souvent lorsqu’un client e-mail envoie un message uniquement en HTML, sans version en texte brut. Il n’a été envoyé à personne.

Veuillez réessayer en incluant du texte brut.

— %2$s','[%1$s] Community message from %2$s'=>'[%1$s] Message de la communauté de %2$s','%1$s <%2$s> sent a message to the community:'=>'%1$s <%2$s> a envoyé un message à la communauté :','Subject: %s'=>'Objet : %s','Hit reply to respond — your reply goes back to the whole community, translated automatically, just like this message.'=>'Répondez pour répondre — votre réponse sera renvoyée à toute la communauté, traduite automatiquement, tout comme ce message.','This message was sent by %s.'=>'Ce message a été envoyé par %s.','%1$s via %2$s'=>'%1$s via %2$s','no limit'=>'aucune limite','Hi %1$s,

The %2$s community has opened a vote to change the membership size cap to %3$s. The vote closes on %4$s.

A strict majority of active members (more than 50%%) must vote yes for the new cap to be adopted. Sign in to your account to cast your vote.

— %2$s'=>'Bonjour %1$s,

La communauté %2$s a ouvert un vote pour modifier le plafond de taille d’adhésion à %3$s. Le vote se clôture le %4$s.

Une majorité absolue des membres actifs (plus de 50%%) doit voter pour que le nouveau plafond soit adopté. Connectez-vous à votre compte pour voter.

— %2$s','Community size-cap vote open at %s'=>'Vote sur le plafond de taille de la communauté ouvert sur %s','Community size cap changed at %s'=>'Plafond de taille de la communauté modifié sur %s','The community voted to change the membership size cap to %1$s (proposal #%2$d). The new cap is now in effect.'=>'La communauté a voté pour modifier le plafond de taille d’adhésion à %1$s (proposition n° %2$d). Le nouveau plafond est désormais en vigueur.','Community size-cap proposal did not pass at %s'=>'Proposition de plafond de taille de la communauté non adoptée sur %s','A community vote to change the membership size cap (proposal #%1$d) closed without a majority. The cap is unchanged.'=>'Un vote de la communauté visant à modifier le plafond de taille d’adhésion (proposition n° %1$d) s’est clôturé sans majorité. Le plafond reste inchangé.','Only community members can do this.'=>'Seuls les membres de la communauté peuvent faire cela.','The cap must be zero or a positive number.'=>'Le plafond doit être égal à zéro ou à un nombre positif.','That is already the current cap.'=>'C’est déjà le plafond actuel.','A different cap proposal is already under way. Resolve or co-sign that one first.'=>'Une autre proposition de plafond est déjà en cours. Résolvez-la ou cosignez-la d’abord.','No active proposal to co-sign.'=>'Aucune proposition active à cosigner.','Proposal not found.'=>'Proposition introuvable.','This vote is not currently open.'=>'Ce vote n’est actuellement pas ouvert.','This artist can\'t be reached through this form right now.'=>'Cet artiste ne peut pas être contacté via ce formulaire pour le moment.','Thanks — your message has been sent.'=>'Merci — votre message a été envoyé.','Spam, scams, or unsolicited commercial advertising unrelated to genuinely contacting the artist about their work'=>'Spam, arnaques ou publicité commerciale non sollicitée sans rapport avec un vrai contact avec l’artiste à propos de son travail','Flagged by automatic content review.'=>'Signalé par l’examen automatique du contenu.','New message from %s via your Agnosis contact form'=>'Nouveau message de %s via votre formulaire de contact Agnosis','From: %s'=>'De : %s','(no name provided)'=>'(aucun nom fourni)','Email: %s'=>'E-mail : %s','Original message, as submitted:'=>'Message original, tel qu’il a été envoyé :','Your name (optional)'=>'Votre nom (facultatif)','Your email address'=>'Votre adresse e-mail','you@example.com'=>'vous@exemple.com','Send message'=>'Envoyer le message','Thanks — your message has been sent. You can reach out to this artist again a little later.'=>'Merci — votre message a été envoyé. Vous pourrez recontacter cet artiste un peu plus tard.','Something went wrong. Please try again.'=>'Une erreur s’est produite. Veuillez réessayer.','Authentication required.'=>'Authentification requise.','This field cannot be edited here.'=>'Ce champ ne peut pas être modifié ici.','That date could not be understood.'=>'Cette date n’a pas pu être comprise.','That does not look like a valid timezone (e.g. "Europe/Madrid").'=>'Cela ne ressemble pas à un fuseau horaire valide (par ex. « Europe/Madrid »).','That does not look like a valid link (must start with http:// or https://).'=>'Cela ne ressemble pas à un lien valide (doit commencer par http:// ou https://).','The title cannot be empty.'=>'Le titre ne peut pas être vide.','Saved — translations will update within a few minutes.'=>'Enregistré — les traductions seront mises à jour d’ici quelques minutes.','No image file was received.'=>'Aucun fichier image n’a été reçu.','Please upload a JPEG, PNG, WebP, or GIF image.'=>'Veuillez téléverser une image JPEG, PNG, WebP ou GIF.','The uploaded file could not be read.'=>'Le fichier téléversé n’a pas pu être lu.','Untitled'=>'Sans titre','Photo replaced — the original is kept and can be restored later.'=>'Photo remplacée — l’original est conservé et pourra être restauré plus tard.','There is no photo to restore.'=>'Il n’y a pas de photo à restaurer.','No earlier version of this photo was found.'=>'Aucune version antérieure de cette photo n’a été trouvée.','Restored the earlier photo.'=>'La photo précédente a été restaurée.','Only admitted artists may edit their own content.'=>'Seuls les artistes admis peuvent modifier leur propre contenu.','Content not found.'=>'Contenu introuvable.','Only published content can be corrected here.'=>'Seul le contenu publié peut être corrigé ici.','You may only edit your own content.'=>'Vous ne pouvez modifier que votre propre contenu.','This page is not in your own language. Edit the version in your language instead.'=>'Cette page n’est pas dans votre propre langue. Modifiez plutôt la version dans votre langue.','Unsupported field target.'=>'Cible de champ non prise en charge.','Save'=>'Enregistrer','Cancel'=>'Annuler','Saving…'=>'Enregistrement…','Replace photo'=>'Remplacer la photo','Uploading…'=>'Téléversement…','Restore earlier photo'=>'Restaurer la photo précédente','Restoring…'=>'Restauration…','You have left'=>'Vous avez quitté','Your account and everything you published on %s have been permanently deleted. Nothing tied to you is stored here anymore.'=>'Votre compte et tout ce que vous avez publié sur %s ont été définitivement supprimés. Plus rien vous concernant n’est stocké ici.','Link expired or already used'=>'Lien expiré ou déjà utilisé','This confirmation link has already been used or is no longer valid. If you still want to leave, please request removal again from your account.'=>'Ce lien de confirmation a déjà été utilisé ou n’est plus valide. Si vous souhaitez toujours partir, veuillez redemander la suppression depuis votre compte.','You must be logged in.'=>'Vous devez être connecté.','Artist access required.'=>'Accès artiste requis.','No active membership found for this account.'=>'Aucune adhésion active n’a été trouvée pour ce compte.','You cannot nominate yourself for removal.'=>'Vous ne pouvez pas vous proposer vous-même à la suppression.','Artist not found.'=>'Artiste introuvable.','Removal request not found.'=>'Demande de suppression introuvable.','You cannot vote on your own removal.'=>'Vous ne pouvez pas voter pour votre propre suppression.','Confirm your departure from %s'=>'Confirmez votre départ de %s','Hi %1$s,

We received a request to remove your account and all your published work from %2$s.

If you made this request, click the link below to confirm. This action is permanent and cannot be undone.

%3$s

If you did not make this request, you can ignore this email — your account remains unchanged.

— %2$s'=>'Bonjour %1$s,

Nous avons reçu une demande de suppression de votre compte et de toutes vos œuvres publiées sur %2$s.

Si vous êtes à l’origine de cette demande, cliquez sur le lien ci-dessous pour la confirmer. Cette action est définitive et ne peut pas être annulée.

%3$s

Si vous n’êtes pas à l’origine de cette demande, vous pouvez ignorer cet e-mail — votre compte restera inchangé.

— %2$s','An artist has left %s'=>'Un artiste a quitté %s','%1$s has confirmed their departure from %2$s.

Their account and all published work have been permanently deleted.

— %2$s'=>'%1$s a confirmé son départ de %2$s.

Son compte et toutes ses œuvres publiées ont été supprimés définitivement.

— %2$s','You\'ve left %s'=>'Vous avez quitté %s','Hi %1$s,

This confirms that your account and everything you published on %2$s have been permanently deleted, as you requested.

Nothing tied to you — your artwork, biography, events, or account details — is stored on %2$s anymore.

If you didn\'t request this, please contact the site admin right away.

— %2$s'=>'Bonjour %1$s,

Ceci confirme que votre compte et tout ce que vous avez publié sur %2$s ont été supprimés définitivement, comme vous l\'avez demandé.

Rien qui vous soit lié — vos œuvres, votre biographie, vos événements ou les détails de votre compte — n\'est encore conservé sur %2$s.

Si vous n\'avez pas demandé cela, veuillez contacter immédiatement l\'administrateur du site.

— %2$s','Hi %1$s,

Your membership at %2$s has been temporarily suspended until %3$s.

You will be automatically reinstated on that date. If you have questions, please contact the site admin.

— %2$s'=>'Bonjour %1$s,

Votre adhésion sur %2$s a été temporairement suspendue jusqu\'au %3$s.

Vous serez automatiquement réintégré à cette date. Si vous avez des questions, veuillez contacter l\'administrateur du site.

— %2$s','Hi %1$s,

Your membership at %2$s has been suspended.

If you have questions, please contact the site admin.

— %2$s'=>'Bonjour %1$s,

Votre adhésion sur %2$s a été suspendue.

Si vous avez des questions, veuillez contacter l\'administrateur du site.

— %2$s','Your membership at %s has been suspended'=>'Votre adhésion sur %s a été suspendue','Hi %1$s,

Your temporary suspension at %2$s has ended and your membership has been reinstated. You can now log in and submit work as before.

— %2$s'=>'Bonjour %1$s,

Votre suspension temporaire sur %2$s est terminée et votre adhésion a été rétablie. Vous pouvez maintenant vous connecter et soumettre des œuvres comme auparavant.

— %2$s','Your membership at %s has been reinstated'=>'Votre adhésion sur %s a été rétablie','Hi %1$s,

The %2$s community has opened a vote to remove a member. The vote closes on %3$s.

Cast your vote:

Vote YES (remove): %4$s

Vote NO (keep):    %5$s

A majority of active members (more than 50%%) must vote yes for the removal to proceed. You can change your vote by clicking the other link before the deadline.

— %2$s'=>'Bonjour %1$s,

La communauté %2$s a ouvert un vote pour exclure un membre. Le vote se termine le %3$s.

Votez :

VOTE OUI (exclure) : %4$s

VOTE NON (conserver) :    %5$s

Une majorité des membres actifs (plus de 50%%) doit voter oui pour que l\'exclusion ait lieu. Vous pouvez modifier votre vote en cliquant sur l\'autre lien avant la date limite.

— %2$s','Community removal vote open at %s'=>'Vote de suppression communautaire ouvert sur %s','Community removal vote passed at %s'=>'Vote de suppression communautaire adopté sur %s','The community removal vote has closed with a majority in favor.

The artist\'s account and all published work have been permanently deleted from %1$s.

— %2$s'=>'Le vote de suppression communautaire s\'est clos avec une majorité en faveur.

Le compte de l\'artiste et toutes ses œuvres publiées ont été supprimés définitivement de %1$s.

— %2$s','Community removal vote did not pass at %s'=>'Vote de suppression communautaire non adopté sur %s','The community removal vote has closed. The required majority was not reached and the artist\'s membership remains active.

— %s'=>'Le vote de suppression communautaire est clôturé. La majorité requise n\'a pas été atteinte et l\'adhésion de l\'artiste reste active.

— %s','Please enter a valid email address.'=>'Veuillez saisir une adresse e-mail valide.','wp_mail() reported a failure — check your site\'s outgoing mail configuration.'=>'wp_mail() a signalé un échec — vérifiez la configuration des e-mails sortants de votre site.','You\'re invited to join %s'=>'Vous êtes invité à rejoindre %s','[TEST] %s'=>'[TEST] %s','You\'re invited'=>'Vous êtes invité','Apply to join'=>'Demander à rejoindre','No account needed to apply — the community reviews and votes on every application.'=>'Aucun compte n\'est nécessaire pour postuler — la communauté examine et vote sur chaque candidature.','You are already an admitted Agnosis artist.'=>'Vous êtes déjà un artiste Agnosis admis.','Your name'=>'Votre nom','required'=>'obligatoire','Email address'=>'Adresse e-mail','Short bio'=>'Courte biographie','A few sentences about your practice, medium, and background.'=>'Quelques phrases sur votre pratique, votre medium et votre parcours.','Portfolio URL'=>'URL du portfolio','Why do you want to join?'=>'Pourquoi souhaitez-vous rejoindre ?','Language you work in'=>'Langue dans laquelle vous travaillez','Select your language'=>'Sélectionnez votre langue','Helps us communicate and translate content in your language.'=>'Cela nous aide à communiquer et à traduire le contenu dans votre langue.','Apply'=>'Postuler','Almost there — check your inbox for a confirmation email and click the link to open your application for community review.'=>'Vous y êtes presque — vérifiez votre boîte de réception pour un e-mail de confirmation et cliquez sur le lien pour ouvrir votre candidature à l\'examen de la communauté.','Please fill in all required fields.'=>'Veuillez remplir tous les champs obligatoires.','This preferences link is invalid or has been tampered with.'=>'Ce lien de préférences est invalide ou a été modifié.','This preferences link is no longer valid for this account.'=>'Ce lien de préférences n\'est plus valide pour ce compte.','Notification preferences'=>'Préférences de notification','Mute community broadcast messages from other artists.'=>'Couper les messages de diffusion de la communauté provenant des autres artistes.','Application vote emails'=>'E-mails de vote sur les candidatures','Instantly, one email per application (default).'=>'Immédiatement, un e-mail par candidature (par défaut).','Once a day, a single digest of every application still awaiting my vote.'=>'Une fois par jour, un résumé unique de toutes les candidatures qui attendent encore mon vote.','Turn off the contact form on my page — visitors won\'t be able to message me.'=>'Désactiver le formulaire de contact sur ma page — les visiteurs ne pourront pas m\'envoyer de message.','Save preferences'=>'Enregistrer les préférences','Community broadcasts are now muted.'=>'Les messages de diffusion de la communauté sont désormais coupés.','You\'ll continue to receive community broadcasts.'=>'Vous continuerez à recevoir les messages de diffusion de la communauté.','You\'ll receive one daily digest of applications awaiting your vote.'=>'Vous recevrez un résumé quotidien des candidatures en attente de votre vote.','You\'ll receive an email as soon as each new application arrives.'=>'Vous recevrez un e-mail dès qu\'une nouvelle candidature arrivera.','The contact form on your page is now turned off.'=>'Le formulaire de contact sur votre page est désormais désactivé.','Visitors can still reach you through the contact form on your page.'=>'Les visiteurs peuvent toujours vous contacter via le formulaire de contact sur votre page.','Preferences saved'=>'Préférences enregistrées','Artworks'=>'Œuvres','Write about this artwork…'=>'Écrire à propos de cette œuvre…','Biographies'=>'Biographies','Biography'=>'Biographie','Add New Biography'=>'Ajouter une nouvelle biographie','Edit Biography'=>'Modifier la biographie','New Biography'=>'Nouvelle biographie','View Biography'=>'Voir la biographie','Search Biographies'=>'Rechercher des biographies','No biographies found.'=>'Aucune biographie trouvée.','No biographies in trash.'=>'Aucune biographie dans la corbeille.','All Biographies'=>'Toutes les biographies','Events'=>'Événements','Event'=>'Événement','Add New Event'=>'Ajouter un nouvel événement','Edit Event'=>'Modifier l’événement','New Event'=>'Nouvel événement','View Event'=>'Voir l’événement','Search Events'=>'Rechercher des événements','No events found.'=>'Aucun événement trouvé.','No events in trash.'=>'Aucun événement dans la corbeille.','All Events'=>'Tous les événements','Medium'=>'Médium','Mediums'=>'Médiums','Search Mediums'=>'Rechercher des médiums','All Mediums'=>'Tous les médiums','Edit Medium'=>'Modifier le médium','Update Medium'=>'Mettre à jour le médium','Add New Medium'=>'Ajouter un nouveau médium','New Medium Name'=>'Nom du nouveau médium','Artwork'=>'Œuvre','Add New'=>'Ajouter nouveau','Add New Artwork'=>'Ajouter une nouvelle œuvre','Edit Artwork'=>'Modifier l’œuvre','New Artwork'=>'Nouvelle œuvre','View Artwork'=>'Voir l’œuvre','Search Artworks'=>'Rechercher des œuvres','No artworks found.'=>'Aucune œuvre trouvée.','No artworks in trash.'=>'Aucune œuvre dans la corbeille.','All Artworks'=>'Toutes les œuvres','Artwork Archives'=>'Archives des œuvres','Artwork Attributes'=>'Attributs de l’œuvre','Invalid vote link.'=>'Lien de vote invalide.','This vote link is invalid or has been tampered with.'=>'Ce lien de vote est invalide ou a été modifié.','Voter account not found.'=>'Compte de votant introuvable.','Vote to remove this artist from the community?'=>'Voter pour retirer cet artiste de la communauté ?','Vote to keep this artist in the community?'=>'Voter pour garder cet artiste dans la communauté ?','Your vote will be recorded once you confirm below.'=>'Votre vote sera enregistré une fois que vous confirmerez ci-dessous.','Confirm my vote'=>'Confirmer mon vote','You voted to remove this artist from the community.'=>'Vous avez voté pour retirer cet artiste de la communauté.','You voted to keep this artist in the community.'=>'Vous avez voté pour maintenir cet artiste dans la communauté.','%d vote to remove recorded so far.'=>'%d vote pour le retrait enregistré jusqu’à présent.' . "\0" . '%d votes pour le retrait enregistrés jusqu’à présent.','Vote recorded'=>'Vote enregistré','Vote error'=>'Erreur de vote','%d application awaiting your vote'=>'%d candidature en attente de votre vote' . "\0" . '%d candidatures en attente de votre vote','Here\'s your daily digest of applications to %1$s still awaiting your vote. Each has a %2$d-day voting window from when it was confirmed.'=>'Voici votre récapitulatif quotidien des candidatures à %1$s qui attendent toujours votre vote. Chacune dispose d’une fenêtre de vote de %2$d jours à partir de sa validation.','Prefer these one at a time again? You can switch back any time from your notification preferences link below.'=>'Vous préférez à nouveau les recevoir une par une ? Vous pouvez revenir en arrière à tout moment depuis le lien de vos préférences de notification ci-dessous.','Vote in favor of this application?'=>'Voter en faveur de cette candidature ?','Vote against this application?'=>'Voter contre cette candidature ?','You voted in favor of this application.'=>'Vous avez voté en faveur de cette candidature.','You voted against this application.'=>'Vous avez voté contre cette candidature.','%d positive vote recorded so far.'=>'%d vote positif enregistré jusqu’à présent.' . "\0" . '%d votes positifs enregistrés jusqu’à présent.','is active and configured for'=>'est actif et configuré pour','Subdomain'=>'Sous-domaine','routing mode'=>'mode de routage','This conflicts with Agnosis artist subdomains — both plugins would claim the same subdomain namespace.'=>'Cela entre en conflit avec les sous-domaines d’artistes d’Agnosis — les deux extensions revendiqueraient le même espace de noms de sous-domaines.','Artist subdomain routing is'=>'Le routage des sous-domaines d’artistes est','completely inactive'=>'complètement inactif','until this is resolved.'=>'jusqu’à ce que cela soit résolu.','Fix: open'=>'Correction : ouvrez','Settings'=>'Réglages','Language Router'=>'Language Router','and switch the URL strategy to'=>'et basculez la stratégie d’URL vers','Path prefix (subfolder)'=>'Préfixe de chemin (sous-dossier)','This is the LinguaForge default and allows artist subdomains to coexist with language subfolders'=>'C’est le réglage par défaut de LinguaForge et cela permet aux sous-domaines d’artistes de coexister avec les sous-dossiers de langue','Agnosis — Artist Subdomain Routing is disabled'=>'Agnosis — Le routage par sous-domaine d’artiste est désactivé','Open LinguaForge Settings'=>'Ouvrir les réglages de LinguaForge','Agnosis Artist'=>'Artiste Agnosis','My Submissions'=>'Mes envois','Join'=>'Rejoindre','Send new artwork to be published.'=>'Envoyer une nouvelle œuvre à publier.','Update your artist biography.'=>'Mettre à jour votre biographie d’artiste.','Announce an upcoming event.'=>'Annoncer un événement à venir.','Replace'=>'Remplacer','Send a new version of an existing artwork — subject must match its title.'=>'Envoyer une nouvelle version d’une œuvre existante — l’objet doit correspondre à son titre.','Request an existing artwork or event be taken down — subject must match its title.'=>'Demander le retrait d’une œuvre ou d’un événement existant — l’objet doit correspondre à son titre.','Promote'=>'Promouvoir','Choose which artwork represents you in the shared community gallery on the main site — subject must match its title. Your own subdomain already shows everything you\'ve published.'=>'Choisir quelle œuvre vous représente dans la galerie communautaire partagée sur le site principal — l’objet doit correspondre à son titre. Votre propre sous-domaine affiche déjà tout ce que vous avez publié.','Photo-only'=>'Photo uniquement','Publish a photo exactly as sent — no AI enhancement, no quality check.'=>'Publier une photo exactement telle qu’envoyée — aucune amélioration par IA, aucun contrôle qualité.','Pure'=>'Pur','Publish exactly as sent — no AI at all, not even the title/description pass.'=>'Publier exactement tel qu’envoyé — aucune IA du tout, même pas pour le passage du titre/de la description.','Send a message to every other artist in the community.'=>'Envoyer un message à tous les autres artistes de la communauté.','Spotted something to fix after publishing? Log in and look for the pencil icon on your published page — you can correct the title, text, or photo yourself, no need to email us again.'=>'Vous avez repéré quelque chose à corriger après la publication ? Connectez-vous et cherchez l’icône crayon sur votre page publiée — vous pouvez corriger vous-même le titre, le texte ou la photo, sans avoir besoin de nous renvoyer un e-mail.','Manage notification preferences: %s'=>'Gérer les préférences de notification : %s','Manage notification preferences'=>'Gérer les préférences de notification','Agnosis Membership Application'=>'Demande d’adhésion à Agnosis','Agnosis Governance Participation'=>'Participation à la gouvernance d’Agnosis','Agnosis Newsletter Subscription'=>'Abonnement à la newsletter d’Agnosis','Agnosis Newsletter Delivery History'=>'Historique de livraison de la newsletter d’Agnosis','Agnosis Contact Messages Sent'=>'Messages de contact Agnosis envoyés','Agnosis Transactions'=>'Transactions Agnosis','Agnosis Notification Preferences'=>'Préférences de notification Agnosis','Display name'=>'Nom affiché','Application statement'=>'Déclaration de candidature','Language'=>'Langue','Applied at'=>'Date de candidature','Resolved at'=>'Date de résolution','Type'=>'Type','Community vouch given'=>'Appui communautaire accordé','Date'=>'Date','Admission vouch given'=>'Appui d’admission accordé','Community removal vote'=>'Vote de suppression communautaire','Vote'=>'Vote','Community size-cap vote'=>'Vote sur la capacité maximale de la communauté','Locale'=>'Paramètre régional','Subscribed at'=>'Date d’abonnement','Confirmed at'=>'Date de confirmation','Unsubscribed at'=>'Date de désabonnement','Issue'=>'Sujet','Recipient type'=>'Type de destinataire','Queued at'=>'Date de mise en file d’attente','Sent to artist'=>'Envoyé à l’artiste','Translated message'=>'Message traduit','Rejection reason'=>'Motif du refus','IP address'=>'Adresse IP','Sent at'=>'Date d’envoi','Amount'=>'Montant','Currency'=>'Devise','Fee'=>'Frais','Gateway'=>'Passerelle','Your membership application/account is still active. To remove this data, use the "leave the network" link from any Agnosis email, or ask an administrator.'=>'Votre demande d’adhésion/compte est toujours active. Pour supprimer ces données, utilisez le lien « quitter le réseau » depuis n’importe quel e-mail Agnosis, ou demandez à un administrateur.','Your biography, statement, and portfolio link were erased. Your email address was kept on file — your account is currently banned, and it\'s the only way this site can continue to enforce that.'=>'Votre biographie, votre déclaration et le lien vers votre portfolio ont été supprimés. Votre adresse e-mail a été conservée — votre compte est actuellement banni, et c’est le seul moyen pour ce site de faire respecter cette mesure.','[message removed]'=>'[message supprimé]','Vouch messages you wrote were redacted. Governance votes you cast were kept as-is — a vote is a community record, not personal data, and removing it would silently change a settled decision.'=>'Les messages d’appui que vous avez rédigés ont été expurgés. Les votes de gouvernance que vous avez émis ont été conservés tels quels — un vote est un enregistrement communautaire, pas une donnée personnelle, et le supprimer modifierait silencieusement une décision déjà actée.','Past newsletter delivery records were anonymized; per-issue delivery counts were kept for statistics.'=>'Les anciens enregistrements de livraison de la newsletter ont été anonymisés ; les comptes de livraison par numéro ont été conservés à des fins statistiques.','Transaction (donation/sale) records were kept in full — financial records are subject to a legal retention obligation and are exempt from erasure under GDPR Art. 17(3)(b).'=>'Les enregistrements des transactions (dons/ventes) ont été conservés intégralement — les registres financiers sont soumis à une obligation légale de conservation et sont exemptés du droit à l’effacement au titre de l’article 17(3)(b) du RGPD.','Agnosis is a federated art-publishing plugin. The following is a starting point for describing what it collects — review and adapt it to your site\'s actual configuration before publishing.'=>'Agnosis est un plugin fédéré de publication artistique. Ce qui suit est un point de départ pour décrire ce qu’il collecte — veuillez le vérifier et l’adapter à la configuration réelle de votre site avant de publier.','What personal data we collect and why'=>'Quelles données personnelles nous collectons et pourquoi','When you apply to join, we store your email address, display name, biography, statement, and portfolio link to run the community vouching process. When you email us artwork, a biography, or an event, the content of that email (including your address) is stored while it is processed and reviewed. When you subscribe to our newsletter or message an artist through their contact form, we store your email address (and, for contact messages, your IP address) to deliver that message or send you future issues.'=>'Lorsque vous demandez à rejoindre la communauté, nous stockons votre adresse e-mail, votre nom affiché, votre biographie, votre déclaration et le lien vers votre portfolio afin de gérer le processus d’appui communautaire. Lorsque vous nous envoyez une œuvre, une biographie ou un événement par e-mail, le contenu de cet e-mail (y compris votre adresse) est stocké pendant son traitement et son examen. Lorsque vous vous abonnez à notre newsletter ou contactez un artiste via son formulaire de contact, nous stockons votre adresse e-mail (et, pour les messages de contact, votre adresse IP) afin de transmettre ce message ou de vous envoyer les prochains numéros.','Who we share it with'=>'Avec qui nous les partageons','Submitted artwork descriptions and images may be sent to a third-party AI provider (OpenAI, Anthropic, or Stability AI, depending on this site\'s configuration) to help write publication text and enhance images. Approved posts are also broadcast publicly over ActivityPub (the Fediverse) as part of this plugin\'s core federation feature.'=>'Les descriptions et images des œuvres soumises peuvent être envoyées à un fournisseur d’IA tiers (OpenAI, Anthropic ou Stability AI, selon la configuration de ce site) pour aider à rédiger le texte de publication et à améliorer les images. Les publications approuvées sont également diffusées publiquement via ActivityPub (le Fediverse) dans le cadre de la fonctionnalité de fédération principale de ce plugin.','How long we retain your data'=>'Combien de temps nous conservons vos données','Retention varies by data type; see this site\'s administrator for specifics. You can request a copy of, or the erasure of, the personal data described above at any time using this site\'s standard WordPress data request tools.'=>'La durée de conservation varie selon le type de données ; adressez-vous à l’administrateur de ce site pour plus de détails. Vous pouvez à tout moment demander une copie des données personnelles décrites ci-dessus, ou leur effacement, à l’aide des outils standard de demande de données de WordPress de ce site.','Submitted text and images may be processed by a third-party AI provider. Approved posts are published publicly and shared across the Fediverse — this cannot be fully undone later.'=>'Le texte et les images soumis peuvent être traités par un fournisseur d’IA tiers. Les publications approuvées sont publiées publiquement et partagées sur le Fediverse — cela ne peut pas être entièrement annulé par la suite.','Your message may be reviewed by an automated content filter before being sent to the artist.'=>'Votre message peut être examiné par un filtre de contenu automatisé avant d’être envoyé à l’artiste.','See our %s for details.'=>'Consultez notre %s pour plus de détails.','Privacy Policy'=>'Politique de confidentialité','Too many requests. Please wait %d seconds and try again.'=>'Trop de demandes. Veuillez attendre %d secondes puis réessayer.','Submission limit reached. Please wait before sending again.'=>'Limite d’envoi atteinte. Veuillez patienter avant de renvoyer.','Please complete the verification check and try again.'=>'Veuillez compléter la vérification puis réessayer.','Could not verify you\'re human right now. Please try again in a moment.'=>'Impossible de vérifier que vous êtes humain pour le moment. Veuillez réessayer dans un instant.','Verification failed. Please try again.'=>'La vérification a échoué. Veuillez réessayer.','Every 5 minutes'=>'Toutes les 5 minutes','IMAP credentials are not configured.'=>'Les identifiants IMAP ne sont pas configurés.','Connected successfully. %1$d message(s) in inbox, %2$d unseen.'=>'Connexion réussie. %1$d message(s) dans la boîte de réception, %2$d non lus.','Webhook secret not configured.'=>'Le secret du webhook n’est pas configuré.','Invalid or missing webhook signature.'=>'Signature du webhook invalide ou manquante.','Webhook request timestamp is missing, malformed, or too old.'=>'L’horodatage de la requête webhook est manquant, mal formé ou trop ancien.','This webhook request has already been processed.'=>'Cette requête webhook a déjà été traitée.','OpenSSL is required for HTTP Signature verification.'=>'OpenSSL est requis pour la vérification de la signature HTTP.','Signature header is required.'=>'L’en-tête Signature est requis.','Signature header is missing required fields (keyId, headers, signature).'=>'L’en-tête Signature est incomplet (keyId, headers, signature).','Request date is too old or too far in the future.'=>'La date de la requête est trop ancienne ou trop éloignée dans le futur.','Signature value is not valid base64.'=>'La valeur de la signature n’est pas un base64 valide.','HTTP Signature verification failed.'=>'La vérification de la signature HTTP a échoué.','Digest header does not match the request body.'=>'L’en-tête Digest ne correspond pas au corps de la requête.','keyId in Signature header is not a valid URL.'=>'keyId dans l’en-tête Signature n’est pas une URL valide.','Failed to fetch actor document.'=>'Échec de la récupération du document de l’actor.','Actor document returned a non-200 response.'=>'Le document de l’actor a renvoyé une réponse autre que 200.','Actor document does not contain a publicKey.publicKeyPem field.'=>'Le document de l’actor ne contient pas de champ publicKey.publicKeyPem.','Node URL is required.'=>'L’URL du nœud est requise.','Contact %s'=>'Contacter %s','Contact this artist'=>'Contacter cet artiste','Get in touch with %s'=>'Prendre contact avec %s','Get in touch'=>'Prendre contact','This newsletter issue could not be found.'=>'Ce numéro de newsletter est introuvable.','Issue not found'=>'Numéro introuvable','Newsletter archive'=>'Archive de la newsletter','Past issues of the %s newsletter.'=>'Anciens numéros de la newsletter %s.','No issues have gone out yet — check back soon.'=>'Aucun numéro n’a encore été publié — revenez bientôt.','← Newer'=>'← Plus récent','Older →'=>'Plus ancien →','Newsletter archive — %s'=>'Archive de la newsletter — %s','%1$s Newsletter — %2$s'=>'Newsletter %1$s — %2$s','%s Newsletter'=>'Newsletter %s','Nothing new to report this time — but the community is still here, and the next issue will have more.'=>'Rien de nouveau à signaler cette fois — mais la communauté est toujours là, et le prochain numéro en dira plus.','New artwork'=>'Nouvelle œuvre','Upcoming events'=>'Événements à venir','%d new artwork published'=>'%d nouvelle œuvre publiée' . "\0" . '%d nouvelles œuvres publiées','%d new event announced'=>'%d nouvel événement annoncé' . "\0" . '%d nouveaux événements annoncés','Welcome to our newest member: %s'=>'Bienvenue à notre nouveau membre : %s' . "\0" . 'Bienvenue à nos nouveaux membres : %s','%d community vote is open — check your email for your personal voting link.'=>'%d vote communautaire est ouvert — consultez votre e-mail pour votre lien de vote personnel.' . "\0" . '%d votes de la communauté sont ouverts — consultez votre e-mail pour vos liens de vote personnels.','Recent work from the community'=>'Travaux récents de la communauté','…and %d more.'=>'…et %d de plus.' . "\0" . '…et %d de plus.','Community Newsletter'=>'Newsletter de la communauté','Having trouble viewing this email?'=>'Vous avez des difficultés à afficher cet e-mail ?','View it online.'=>'Consultez-le en ligne.','Unsubscribe'=>'Se désabonner','Subscribe to get these by email'=>'S’abonner pour les recevoir par e-mail','[%s] Community newsletter'=>'[%s] Newsletter de la communauté','[%s] Newsletter'=>'[%s] Newsletter','Get new artworks, artist admissions, and community updates in your inbox.'=>'Recevez de nouvelles œuvres, les admissions d’artistes et les actualités de la communauté dans votre boîte de réception.','Subscribe to the newsletter'=>'S’abonner à la newsletter','Unknown newsletter type.'=>'Type de newsletter inconnu.','A previous issue is still sending — please wait for it to finish.'=>'Une édition précédente est toujours en cours d’envoi — veuillez attendre qu’elle soit terminée.','Please enter a valid email address to send the test to.'=>'Veuillez saisir une adresse e-mail valide pour envoyer le test.','This is a TEST send — it previews the next issue using the current draft intro and recent activity. It was not counted as a real send and no subscribers were emailed. The unsubscribe link below is a non-functional placeholder.'=>'Il s’agit d’un envoi DE TEST — il affiche un aperçu du prochain numéro en utilisant l’introduction brouillon actuelle et l’activité récente. Il n’a pas été compté comme un envoi réel et aucun abonné n’a reçu d’e-mail. Le lien de désabonnement ci-dessous est un espace réservé non fonctionnel.','The %1$s at %2$s is due to send in about a day. Agnosis drafted an intro from what\'s new since the last issue:'=>'Le %1$s de %2$s doit être envoyé d’ici environ un jour. Agnosis a rédigé une introduction à partir des nouveautés depuis le dernier numéro :','It\'s already saved and will be used as-is if you don\'t act — review it, rewrite it, or clear it back to blank here:'=>'C’est déjà enregistré et cela sera utilisé tel quel si vous n’intervenez pas — relisez-le, réécrivez-le ou remettez-le à vide ici :','%1$s intro drafted for %2$s — review before it sends'=>'Introduction de %1$s rédigée pour %2$s — à vérifier avant l’envoi','Subscribe'=>'S’abonner','See past issues'=>'Voir les anciens numéros','Almost there — check your inbox for a confirmation link.'=>'Presque terminé — consultez votre boîte de réception pour un lien de confirmation.','[%s] Confirm your newsletter subscription'=>'[%s] Confirmez votre abonnement à la newsletter','Thanks for signing up! Confirm your email address to start receiving the newsletter.'=>'Merci de vous être inscrit·e ! Confirmez votre adresse e-mail pour commencer à recevoir la newsletter.','Confirm subscription'=>'Confirmer l’abonnement','If you didn\'t request this, simply ignore this email — you will not be subscribed.'=>'Si vous n’avez pas fait cette demande, ignorez simplement cet e-mail — vous ne serez pas abonné·e.','Artists are automatically subscribed — there is nothing to confirm.'=>'Les artistes sont automatiquement abonné·es — il n’y a rien à confirmer.','Subscription confirmed'=>'Abonnement confirmé','You\'re all set — the newsletter will land in your inbox from now on.'=>'C’est tout bon — la newsletter arrivera désormais dans votre boîte de réception.','Unsubscribed'=>'Désabonné','You will no longer receive the newsletter. Sorry to see you go.'=>'Vous ne recevrez plus la newsletter. Nous sommes désolé·es de vous voir partir.','This unsubscribe link is invalid or has already been used.'=>'Ce lien de désabonnement est invalide ou a déjà été utilisé.','This unsubscribe link is invalid or has been tampered with.'=>'Ce lien de désabonnement est invalide ou a été altéré.','Account not found.'=>'Compte introuvable.','You will no longer receive the artist newsletter. You can re-subscribe any time from your submissions page.'=>'Vous ne recevrez plus la newsletter des artistes. Vous pouvez vous réabonner à tout moment depuis votre page de soumissions.','Confirm your subscription?'=>'Confirmer votre abonnement ?','You\'ll start receiving the newsletter once you confirm below.'=>'Vous commencerez à recevoir la newsletter une fois la confirmation ci-dessous effectuée.','Unsubscribe from the newsletter?'=>'Se désabonner de la newsletter ?','You will stop receiving the newsletter once you confirm below.'=>'Vous cesserez de recevoir la newsletter une fois la confirmation ci-dessous effectuée.','Confirm unsubscribe'=>'Confirmer le désabonnement','That doesn\'t look like a valid web address.'=>'Cela ne ressemble pas à une adresse web valide.','This site isn\'t on this Agnosis node\'s list of trusted platforms, and automatic link review is turned off here.'=>'Ce site ne figure pas dans la liste des plateformes de confiance de ce nœud Agnosis, et la vérification automatique des liens est désactivée ici.','This node couldn\'t safely load that page to review it (it may be unreachable, or blocked for security reasons).'=>'Ce nœud n’a pas pu charger cette page en toute sécurité pour la vérifier (elle est peut-être inaccessible, ou bloquée pour des raisons de sécurité).','Automatic review of that page\'s content was inconclusive.'=>'La vérification automatique du contenu de cette page n’a pas été concluante.','Automatic review found that page\'s content isn\'t allowed to be embedded on this site.'=>'La vérification automatique a déterminé que le contenu de cette page ne peut pas être intégré sur ce site.','Gallery overview'=>'Aperçu de la galerie','Feature this artwork in the gallery overview'=>'Mettre cette œuvre en avant dans l’aperçu de la galerie','Featured artworks are always chosen first when selecting one work per artist for the homepage overview.'=>'Les œuvres mises en avant sont toujours choisies en priorité lors de la sélection d’une œuvre par artiste pour l’aperçu de la page d’accueil.','[Agnosis] Confirm removal of: %s'=>'[Agnosis] Confirmer la suppression de : %s','[%s] We couldn\'t find that artwork or event'=>'[%s] Nous n’avons pas trouvé cette œuvre ou cet événement','[%s] Your artwork is now featured'=>'[%s] Votre œuvre est maintenant mise en avant','[%s] We couldn\'t find that artwork'=>'[%s] Nous n’avons pas trouvé cette œuvre','We received a removal request for "%s", but couldn\'t find an artwork or event with that exact title in your account.'=>'Nous avons reçu une demande de suppression pour « %s », mais nous n’avons trouvé dans votre compte ни une œuvre ni un événement portant exactement ce titre.','We received a request to feature "%s", but couldn\'t find a published artwork with that exact title in your account.'=>'Nous avons reçu une demande de mise en avant pour « %s », mais nous n’avons trouvé dans votre compte aucune œuvre publiée portant exactement ce titre.','Did you mean "%s"?'=>'Vouliez-vous dire « %s » ?','Yes, remove this instead'=>'Oui, supprimez plutôt ceci','Or simply resend your original email with that exact title.'=>'Ou renvoyez simplement votre e-mail d’origine avec ce titre exact.','Resend your original email with that exact title.'=>'Renvoyez votre e-mail d’origine avec ce titre exact.','Your current titles:'=>'Vos titres actuels :','Titles are matched exactly, so a small difference in wording is enough to miss — double-check spelling, capitalization, and punctuation against the list above before resending.'=>'Les titres doivent correspondre exactement, donc une petite différence de formulation suffit à passer à côté — vérifiez bien l’orthographe, les majuscules et la ponctuation par rapport à la liste ci-dessus avant de renvoyer.','"%s" is now your featured artwork on the gallery overview.'=>'« %s » est maintenant votre œuvre mise en avant sur l’aperçu de la galerie.','Any previously featured artwork has been unfeatured automatically — only one piece is featured at a time.'=>'Toute œuvre précédemment mise en avant a été automatiquement retirée de la mise en avant — une seule pièce peut être mise en avant à la fois.','[Agnosis] Your submission is ready to review: %s'=>'[Agnosis] Votre envoi est prêt à être vérifié : %s','event'=>'événement','artwork'=>'œuvre','We received a removal request for the following %s:'=>'Nous avons reçu une demande de suppression pour le %s suivant :','If you want to permanently remove this %s, click the button below. This action cannot be undone.'=>'Si vous souhaitez supprimer définitivement ce %s, cliquez sur le bouton ci-dessous. Cette action est irréversible.','Yes, remove this %s'=>'Oui, supprimez ce %s','If you did not request this removal, simply ignore this email — your %s will remain published.'=>'Si vous n’avez pas demandé cette suppression, ignorez simplement cet e-mail — votre %s restera publié.','This confirmation link expires in 7 days.'=>'Ce lien de confirmation expire dans 7 jours.','📷 Photo enhanced automatically'=>'📷 Photo améliorée automatiquement','We detected some photographic issues and applied AI correction to improve visibility of your artwork:'=>'Nous avons détecté certains problèmes photographiques et appliqué une correction IA pour améliorer la visibilité de votre œuvre :','The artwork itself has not been altered — only the photograph quality was corrected.'=>'L’œuvre elle-même n’a pas été modifiée — seule la qualité de la photo a été corrigée.','📷 Photo quality score: %d/10'=>'📷 Score de qualité de la photo : %d/10','Double-check the link is correct — you can fix or remove it in the form below before publishing.'=>'Vérifiez que le lien est correct — vous pouvez le corriger ou le supprimer dans le formulaire ci-dessous avant la publication.','If the link was correct, its destination may simply not be from a source this site automatically embeds.'=>'Si le lien était correct, sa destination n’est peut-être simplement pas issue d’une source que ce site intègre automatiquement.','🔗 A link was not included'=>'🔗 Aucun lien n’a été inclus' . "\0" . '🔗 Certains liens n’ont pas été inclus','The following couldn\'t be automatically embedded, so they were left out:'=>'Les éléments suivants n’ont pas pu être intégrés automatiquement et ont donc été laissés de côté :','Its subject line didn\'t exactly match one of your existing titles. If you meant to update an existing event, "%s", resend your email with that exact title instead.'=>'Son objet ne correspondait pas exactement à l’un de vos titres existants. Si vous vouliez mettre à jour un événement existant, « %s », renvoyez plutôt votre e-mail avec ce titre exact.','Its subject line didn\'t exactly match one of your existing titles. If you meant to replace an existing artwork, "%s", resend your email with that exact title instead.'=>'Son objet ne correspondait pas exactement à l’un de vos titres existants. Si vous vouliez remplacer une œuvre existante, « %s », renvoyez plutôt votre e-mail avec ce titre exact.','📄 This was published as a new post'=>'📄 Ceci a été publié comme un nouvel article','Your submission has been processed. Here\'s what our AI curator came up with — take a look and let us know if it\'s ready to publish.'=>'Votre envoi a été traité. Voici ce que notre conservateur IA a proposé — regardez et dites-nous s’il est prêt à être publié.','On the site: %s'=>'Sur le site : %s','In your language: %s'=>'Dans votre langue : %s','Looks great — Publish it'=>'Ça a l’air bien — Publier','Discard'=>'Ignorer','Want to tweak the title, text or tags before publishing?'=>'Vous voulez ajuster le titre, le texte ou les tags avant publication ?','Open your submissions page →'=>'Ouvrir votre page des envois →','The Publish and Discard links above expire in %d day. Your submission stays as a draft until you decide.'=>'Les liens Publier et Ignorer ci-dessus expirent dans %d jour. Votre envoi reste en brouillon jusqu’à ce que vous décidiez.' . "\0" . 'Les liens Publier et Ignorer ci-dessus expirent dans %d jours. Votre envoi reste en brouillon jusqu’à ce que vous décidiez.','[%s] We couldn\'t process your submission'=>'[%s] Nous n’avons pas pu traiter votre envoi','[%s] We couldn\'t find a photo in your email'=>'[%s] Nous n’avons pas trouvé de photo dans votre e-mail','We received your email, but couldn\'t process a usable photo, audio, or video file from it — so nothing was published. This can happen when an image is pasted or inserted inline rather than added as a proper attachment, or when a file arrives in a format this server can\'t convert (for example, an iPhone photo saved in HEIC/HEIF format).'=>'Nous avons reçu votre e-mail, mais nous n’avons pas pu en extraire un fichier photo, audio ou vidéo exploitable — rien n’a donc été publié. Cela peut se produire lorsqu’une image est collée ou insérée en ligne plutôt qu’ajoutée en pièce jointe, ou lorsqu’un fichier arrive dans un format que ce serveur ne peut pas convertir (par exemple, une photo d’iPhone enregistrée au format HEIC/HEIF).','To resend correctly:'=>'Pour renvoyer correctement :','Use your mail app\'s "Attach file" (usually a paperclip icon) rather than "Insert photo" or pasting the image directly into the message body.'=>'Utilisez l’option « Joindre un fichier » de votre application de messagerie (généralement une icône de trombone) plutôt que « Insérer une photo » ou coller l’image directement dans le corps du message.','If your photo was taken on an iPhone, try switching Settings → Camera → Formats to "Most Compatible" before taking or sending it, or use "Options" in Mail to send it as a JPEG.'=>'Si votre photo a été prise sur un iPhone, essayez de passer dans Réglages → Appareil photo → Formats à « Le plus compatible » avant de la prendre ou de l’envoyer, ou utilisez « Options » dans Mail pour l’envoyer en JPEG.','Supported formats: JPEG, PNG, WebP, GIF, TIFF, or HEIC/HEIF for images; MP3, WAV, M4A, OGG, or FLAC for audio; MP4, MOV, AVI, WebM, OGG, or MPEG for video.'=>'Formats pris en charge : JPEG, PNG, WebP, GIF, TIFF ou HEIC/HEIF pour les images ; MP3, WAV, M4A, OGG ou FLAC pour l’audio ; MP4, MOV, AVI, WebM, OGG ou MPEG pour la vidéo.','Once it\'s properly attached, just send it to the same address again — we\'ll pick it up automatically.'=>'Une fois correctement jointe, envoyez-la simplement à la même adresse — nous la prendrons automatiquement en charge.','The photo is too dark to show your artwork clearly. Try photographing near a large window in daylight, or use a soft lamp aimed at the work from the side.'=>'La photo est trop sombre pour montrer clairement votre œuvre. Essayez de la photographier près d’une grande fenêtre, en plein jour, ou utilisez une lampe douce dirigée sur l’œuvre depuis le côté.','The photo is underexposed (too dark). Try photographing near a large window in daylight, or use a soft lamp aimed at the work from the side.'=>'La photo est sous-exposée (trop sombre). Essayez de la photographier près d’une grande fenêtre, en plein jour, ou utilisez une lampe douce dirigée sur l’œuvre depuis le côté.','The photo is overexposed (too bright / washed out). Avoid direct sunlight or flash pointed straight at the artwork — diffuse or indirect light works best.'=>'La photo est surexposée (trop claire / délavée). Évitez la lumière directe du soleil ou le flash dirigé droit sur l’œuvre — une lumière diffuse ou indirecte fonctionne mieux.','The photo is too bright or washed out. Avoid direct sunlight or flash — diffuse light or shade gives more even tones.'=>'La photo est trop claire ou délavée. Évitez la lumière directe du soleil ou le flash — une lumière diffuse ou l’ombre donnent des tons plus uniformes.','There is glare or a bright reflection on the artwork. Tilt the canvas slightly or photograph at an angle to eliminate reflections from the surface.'=>'Il y a un reflet ou une forte brillance sur l’œuvre. Inclinez légèrement la toile ou photographiez depuis un angle pour éliminer les reflets de la surface.','There is a reflection on the artwork surface. Tilt the canvas slightly or change your angle to eliminate it.'=>'Il y a un reflet sur la surface de l’œuvre. Inclinez légèrement la toile ou changez d’angle pour l’éliminer.','The image is blurry. Rest your phone or camera on a stable surface, use the self-timer, and make sure the artwork fills most of the frame so autofocus locks on it.'=>'L’image est floue. Posez votre téléphone ou appareil photo sur une surface stable, utilisez le retardateur, et assurez-vous que l’œuvre occupe la majeure partie du cadre afin que l’autofocus se verrouille dessus.','The image is out of focus. Tap on the artwork on your phone screen before shooting to make sure autofocus locks on it, and hold the camera still.'=>'L’image est hors mise au point. Touchez l’œuvre sur l’écran de votre téléphone avant de prendre la photo pour que l’autofocus se verrouille dessus, et gardez l’appareil immobile.','There is motion blur. Hold the camera very still or use a tripod; press the shutter gently or use the self-timer to avoid shake.'=>'Il y a un flou de mouvement. Tenez l’appareil très immobile ou utilisez un trépied ; appuyez doucement sur le déclencheur ou utilisez le retardateur pour éviter les vibrations.','Camera shake is visible. Use a tripod or rest the camera on a flat surface and use the self-timer to avoid movement when pressing the shutter.'=>'Des tremblements de l’appareil sont visibles. Utilisez un trépied ou posez l’appareil sur une surface plane et utilisez le retardateur pour éviter tout mouvement au moment d’appuyer sur le déclencheur.','The image resolution is too low. Use your phone\'s highest quality setting and make sure you\'re close enough that the artwork fills the frame.'=>'La résolution de l’image est trop faible. Utilisez le réglage de qualité le plus élevé de votre téléphone et assurez-vous d’être assez proche pour que l’œuvre remplisse le cadre.','The image resolution is too low. Use your phone\'s highest quality setting and fill the frame with the artwork.'=>'La résolution de l’image est trop faible. Utilisez le réglage de qualité le plus élevé de votre téléphone et remplissez le cadre avec l’œuvre.','The image is pixelated. Shoot from closer or use a higher resolution setting on your camera.'=>'L’image est pixellisée. Prenez la photo de plus près ou utilisez un réglage de résolution plus élevé sur votre appareil photo.','The photo has a strong color cast. Shoot under neutral daylight or use your phone\'s Auto White Balance setting for more accurate colors.'=>'La photo a une forte dominante de couleur. Photographiez sous une lumière naturelle neutre ou utilisez le réglage Balance des blancs automatique de votre téléphone pour des couleurs plus fidèles.','The photo looks too yellow or warm. Shoot under natural daylight or switch your phone\'s white balance to Daylight / Cloudy.'=>'La photo paraît trop jaune ou trop chaude. Photographiez à la lumière naturelle du jour ou réglez la balance des blancs de votre téléphone sur Lumière du jour / Nuageux.','The photo has a cold blue tint. Move the artwork to a warmer, more natural light source or adjust your camera\'s white balance.'=>'La photo a une dominante bleue et froide. Déplacez l’œuvre vers une source de lumière plus chaude et plus naturelle ou ajustez la balance des blancs de votre appareil.','Part of the artwork appears to be cropped out of the frame. Step back and make sure the entire work is visible before shooting.'=>'Une partie de l’œuvre semble avoir été coupée du cadre. Reculez et assurez-vous que l’œuvre entière est visible avant de prendre la photo.','The artwork is photographed at an angle, causing distortion. Shoot straight on, with the camera parallel to the canvas.'=>'L’œuvre est photographiée en biais, ce qui provoque une déformation. Photographiez bien de face, avec l’appareil parallèle à la toile.','The artwork looks distorted or skewed. Position your camera directly in front of the artwork, parallel to its surface.'=>'L’œuvre paraît déformée ou inclinée. Placez votre appareil directement en face de l’œuvre, parallèle à sa surface.','There is a shadow across part of the artwork. Reposition your light source or move the artwork so no shadows fall on the surface.'=>'Il y a une ombre sur une partie de l’œuvre. Repositionnez votre source de lumière ou déplacez l’œuvre afin qu’aucune ombre ne tombe sur la surface.','We received your submission, but unfortunately the photo quality is too low for us to show your artwork clearly. We didn\'t publish it — but please don\'t be discouraged! A simple retake is usually all it takes.'=>'Nous avons bien reçu votre envoi, mais malheureusement la qualité de la photo est trop faible pour que nous puissions montrer clairement votre œuvre. Nous ne l’avons pas publiée — mais ne vous découragez pas ! Une simple nouvelle photo suffit généralement.','📷 Photo quality score: %d / 10'=>'📷 Score de qualité de la photo : %d / 10','Here\'s what our AI detected and how to fix it:'=>'Voici ce que notre IA a détecté et comment corriger le problème :','The overall photo quality was too low for our AI to process the artwork clearly.'=>'La qualité globale de la photo était trop faible pour que notre IA puisse traiter l’œuvre clairement.','💡 Quick tips for a great artwork photo'=>'💡 Conseils rapides pour une bonne photo d’œuvre','Use natural light — position the artwork near a window on a cloudy day for even, soft light.'=>'Utilisez la lumière naturelle — placez l’œuvre près d’une fenêtre par temps nuageux pour une lumière douce et uniforme.','Shoot straight on — hold your phone parallel to the canvas to avoid perspective distortion.'=>'Photographiez bien de face — tenez votre téléphone parallèle à la toile pour éviter la distorsion de perspective.','Fill the frame — let the artwork take up most of the shot; crop out distracting backgrounds.'=>'Remplissez le cadre — faites en sorte que l’œuvre occupe la majeure partie de l’image ; coupez les arrière-plans distrayants.','Hold still — tap the artwork on your screen to focus, then press the shutter gently or use a self-timer.'=>'Tenez-vous immobile — touchez l’œuvre sur votre écran pour faire la mise au point, puis appuyez doucement sur le déclencheur ou utilisez le retardateur.','Once you have a clearer photo, just email it to the same address as before — we\'ll pick it up automatically.'=>'Une fois que vous avez une photo plus nette, envoyez-la simplement à la même adresse e-mail qu’auparavant — nous la récupérerons automatiquement.','Your previous submission is saved in your submissions page in case you want to review what was sent.'=>'Votre envoi précédent est enregistré sur votre page des envois si vous souhaitez vérifier ce qui a été envoyé.','View submissions →'=>'Voir les envois →','Photo'=>'Photo','%s (original)'=>'%s (original)','%s (poster frame)'=>'%s (cadre d’affiche)','Failed to insert attachment.'=>'Échec de l’insertion de la pièce jointe.','Artwork or event not found.'=>'Œuvre ou événement introuvable.','%s already removed.'=>'%s déjà supprimé.','Could not remove the %s. Please try again.'=>'Impossible de supprimer le/la %s. Veuillez réessayer.','Your %s has been removed.'=>'Votre %s a été supprimé(e).','A valid removal token is required.'=>'Un jeton de suppression valide est requis.','No pending removal request found for this item.'=>'Aucune demande de suppression en attente n’a été trouvée pour cet élément.','The removal link has expired. Please send another removal request.'=>'Le lien de suppression a expiré. Veuillez envoyer une nouvelle demande de suppression.','Invalid removal token.'=>'Jeton de suppression invalide.','View it live'=>'Voir en ligne','Biography published'=>'Biographie publiée','Your biography has been published.'=>'Votre biographie a été publiée.','Event published'=>'Événement publié','The event has been published.'=>'L’événement a été publié.','Artwork published'=>'Œuvre publiée','The artwork has been published to the gallery.'=>'L’œuvre a été publiée dans la galerie.','Submission discarded'=>'Soumission supprimée','The submission has been discarded.'=>'La soumission a été supprimée.','Biography removed'=>'Biographie supprimée','Your biography has been removed.'=>'Votre biographie a été supprimée.','Event removed'=>'Événement supprimé','The event has been removed.'=>'L’événement a été supprimé.','Artwork removed'=>'Œuvre supprimée','Your artwork has been removed from the gallery.'=>'Votre œuvre a été retirée de la galerie.','This link may have already been used or may have expired. Please log in to manage your submissions.'=>'Ce lien a peut-être déjà été utilisé ou a peut-être expiré. Veuillez vous connecter pour gérer vos soumissions.','Title and full text cannot be empty. Fill them back in, or use "Discard" from the original email instead.'=>'Le titre et le texte complet ne peuvent pas être vides. Renseignez-les à nouveau, ou utilisez plutôt « Supprimer » depuis l’e-mail d’origine.','The full text cannot be empty. Fill it back in, or use "Discard" from the original email instead.'=>'Le texte complet ne peut pas être vide. Renseignez-le à nouveau, ou utilisez plutôt « Supprimer » depuis l’e-mail d’origine.','Portfolio link'=>'Lien du portfolio','Social link %d (optional)'=>'Lien social %d (facultatif)','Hour'=>'Heure','Location'=>'Lieu','Address'=>'Adresse','Timezone'=>'Fuseau horaire','Other'=>'Autre','— Not set —'=>'— Non défini —','Discard this submission?'=>'Supprimer cette soumission ?','This will permanently discard the submission — it will not be published.'=>'Cela supprimera définitivement la soumission — elle ne sera pas publiée.','Yes, discard it'=>'Oui, la supprimer','Remove this artwork?'=>'Retirer cette œuvre ?','This will remove the published artwork from the gallery.'=>'Cela retirera l’œuvre publiée de la galerie.','Yes, remove it'=>'Oui, la retirer','Title'=>'Titre','Short description'=>'Brève description','Full text'=>'Texte complet','Publish this %s?'=>'Publier ce %s ?','Make any final changes below, or leave everything as-is to publish exactly what was drafted.'=>'Apportez ci-dessous vos dernières modifications, ou laissez tout tel quel pour publier exactement ce qui a été rédigé.','Publish it'=>'Le publier','biography'=>'biographie','Submission not found.'=>'Soumission introuvable.','This submission is not awaiting review.'=>'Cette soumission n’est pas en attente de validation.','The original published item could not be found.'=>'L’élément publié d’origine est introuvable.','You do not have permission to review this submission.'=>'Vous n’avez pas l’autorisation de valider cette soumission.','Review link not found or already used.'=>'Lien de relecture introuvable ou déjà utilisé.','Invalid review token.'=>'Jeton de relecture invalide.','This review link has expired. Please log in to manage your submissions.'=>'Ce lien de relecture a expiré. Veuillez vous connecter pour gérer vos soumissions.','No submissions awaiting review.'=>'Aucune soumission en attente de validation.','Make changes'=>'Apporter des modifications','One-line description'=>'Description en une ligne','Description'=>'Description','Tags (comma-separated)'=>'Tags (séparés par des virgules)','Save &amp; Publish'=>'Enregistrer &amp; Publier','Publishing…'=>'Publication…','Published ✓'=>'Publié ✓','Something went wrong.'=>'Une erreur s’est produite.','Could not connect. Please try again.'=>'Impossible de se connecter. Veuillez réessayer.','Discard this submission? This cannot be undone.'=>'Supprimer cette soumission ? Cela ne peut pas être annulé.','Discarding…'=>'Suppression…','Discarded.'=>'Supprimé.','Saving and publishing…'=>'Enregistrement et publication…','Log in to view your submissions'=>'Connectez-vous pour voir vos soumissions','Username or email address'=>'Nom d’utilisateur ou adresse e-mail','Password'=>'Mot de passe','Log in'=>'Se connecter','Remember me'=>'Se souvenir de moi','Forgot your password?'=>'Mot de passe oublié ?','Book'=>'Livre','Person'=>'Personne','Calendar'=>'Calendrier','Pin'=>'Épingle','Baseline (default)'=>'Baseline (par défaut)','Top'=>'Haut','Middle'=>'Milieu','Bottom'=>'Bas','Icon settings'=>'Paramètres des icônes','Biography icon'=>'Icône de biographie','Events icon'=>'Icône des événements','Icon size'=>'Taille de l’icône','Icon vertical align'=>'Alignement vertical de l’icône','Icon-only links have no text baseline of their own — use this if they sit too high or low next to the artist name once Icon size is changed from the default.'=>'Les liens avec icône seule n’ont pas leur propre ligne de base de texte — utilisez ceci s’ils apparaissent trop hauts ou trop bas à côté du nom de l’artiste une fois que la taille de l’icône est modifiée par rapport à la valeur par défaut.','Icon color'=>'Couleur de l’icône','Leave unset to match the block’s own text color.'=>'Laissez vide pour reprendre la couleur du texte du bloc.','Artist Name'=>'Nom de l’artiste','Envelope'=>'Enveloppe','Speech bubble'=>'Bulle de dialogue','Contact'=>'Contact','Link settings'=>'Paramètres des liens','Link type'=>'Type de lien','Icon'=>'Icône','Biography Icon'=>'Icône de biographie','Icon-only link to the artist’s biography.'=>'Lien vers la biographie de l’artiste, sous forme d’icône seule.','Events Icon'=>'Icône des événements','Icon-only link to the artist’s events archive.'=>'Lien vers les archives des événements de l’artiste, sous forme d’icône seule.','Contact Icon'=>'Icône de contact','Opens a popover with a form to message the artist directly. Hidden automatically if the artist has turned contact messages off.'=>'Ouvre une fenêtre contextuelle avec un formulaire pour envoyer un message directement à l’artiste. Masqué automatiquement si l’artiste a désactivé les messages de contact.','Artist Contact Form'=>'Formulaire de contact de l’artiste','Lets a visitor message the current artist subdomain’s artist. Content is rendered live on the frontend, for the artist currently being viewed.'=>'Permet à un visiteur d’envoyer un message à l’artiste du sous-domaine artistique actuellement affiché. Le contenu est rendu en direct sur le site, pour l’artiste en cours de consultation.','Gallery settings'=>'Paramètres de la galerie','Columns'=>'Colonnes','✦ Agnosis Gallery Overview — rendered on the server'=>'✦ Aperçu de la galerie Agnosis — rendu côté serveur','columns · proportional · random daily order'=>'colonnes · proportionnel · ordre aléatoire quotidien','Join Agnosis'=>'Rejoindre Agnosis','Public application form for new artists. Submits name, email, bio, portfolio URL and a personal statement to the community for review. Content is rendered live on the frontend.'=>'Formulaire de candidature public pour les nouveaux artistes. Soumet le nom, l’e-mail, la biographie, l’URL du portfolio et une déclaration personnelle à la communauté pour examen. Le contenu est rendu en direct sur le site.','Place this block on your /join/ page or in a Site Editor page template assigned to that page.'=>'Placez ce bloc sur votre page /join/ ou dans un modèle de page de l’éditeur de site attribué à cette page.','Bell'=>'Cloche','Star'=>'Étoile','Lightning bolt'=>'Éclair','Newsletter Popover — opens the signup form'=>'Popover de newsletter — ouvre le formulaire d’inscription','Newsletter settings'=>'Paramètres de la newsletter','Trigger icon'=>'Icône déclencheuse','Pick something that won’t blend in with icons already sitting next to it (e.g. Social Share).'=>'Choisissez quelque chose qui ne se confondra pas avec les icônes déjà placées à côté (p. ex. Partage social).','Newsletter Signup'=>'Inscription à la newsletter','Email signup form for the public newsletter. A confirmation email is sent before anyone is added to the send list (double opt-in). Content is rendered live on the frontend.'=>'Formulaire d’inscription par e-mail pour la newsletter publique. Un e-mail de confirmation est envoyé avant que quiconque soit ajouté à la liste d’envoi (double opt-in). Le contenu est rendu en direct sur le frontend.','block titleArtist Breadcrumb'=>'Fil d’Ariane de l’artiste','block descriptionSmall line identifying the artist whose subdomain is currently being viewed. Renders nothing on the main Agnosis site.'=>'Petite ligne identifiant l’artiste dont le sous-domaine est actuellement consulté. Ne s’affiche rien sur le site principal d’Agnosis.','block keywordartist'=>'artiste','block keywordbreadcrumb'=>'fil d’Ariane','block keywordsubdomain'=>'sous-domaine','block keywordagnosis'=>'agnosis','block titleArtist Name Link'=>'Lien du nom de l’artiste','block descriptionLinks to the current artist\'s own subdomain home. Renders nothing off an artist subdomain.'=>'Renvoie vers la page d’accueil du sous-domaine de l’artiste courant. Ne s’affiche rien en dehors d’un sous-domaine d’artiste.','block titleBreadcrumb Icon Link'=>'Lien d’icône du fil d’Ariane','block descriptionA single icon-only link (Biography, Events, or a Contact popover) to/about the current artist. Renders nothing if there\'s nothing to show (no biography/events yet, or the artist has turned contact off), or off an artist subdomain.'=>'Un seul lien sous forme d’icône (Biographie, Événements ou un popover de contact) vers/à propos de l’artiste courant. Ne s’affiche rien s’il n’y a rien à afficher (pas encore de biographie/événements, ou l’artiste a désactivé le contact), ni en dehors d’un sous-domaine d’artiste.','block keywordbiography'=>'biographie','block keywordevents'=>'événements','block keywordcontact'=>'contact','block keywordicon'=>'icône','block titleArtist Contact Form'=>'Formulaire de contact de l’artiste','block descriptionContact form letting a visitor message the current artist subdomain\'s artist. Submits to a per-artist REST endpoint; the message is moderated, translated into the artist\'s own language, and emailed to them.'=>'Formulaire de contact permettant à un visiteur d’envoyer un message à l’artiste du sous-domaine courant. L’envoi se fait vers un point de terminaison REST par artiste ; le message est modéré, traduit dans la propre langue de l’artiste, puis envoyé par e-mail.','block keywordmessage'=>'message','block keywordemail'=>'e-mail','block titleAgnosis Gallery Overview'=>'Aperçu de la galerie Agnosis','block descriptionProportional, randomised artwork grid across all artists. Shows featured artworks first, respects per-artist budget, supports medium filtering and pagination.'=>'Grille d’œuvres proportionnelle et aléatoire sur l’ensemble des artistes. Affiche d’abord les œuvres mises en avant, respecte le budget par artiste, prend en charge le filtrage par média et la pagination.','block keywordgallery'=>'galerie','block keywordartwork'=>'œuvre','block keywordartists'=>'artistes','block keywordoverview'=>'aperçu','block titleJoin Agnosis'=>'Rejoindre Agnosis','block descriptionPublic application form for artists who want to join the Agnosis network. Submits to the admission REST endpoint. Place this on your /join/ page.'=>'Formulaire de candidature public pour les artistes qui souhaitent rejoindre le réseau Agnosis. L’envoi se fait vers le point de terminaison REST d’admission. Placez ceci sur votre page /join/.','block keywordjoin'=>'rejoindre','block keywordapply'=>'postuler','block keywordapplication'=>'candidature','block keywordadmission'=>'admission','block titleNewsletter Popover'=>'Popover de newsletter','block descriptionIcon button that opens a full-viewport popover containing the newsletter signup form. Self-contained — drop it directly into a header or footer template part; renders nothing when the public newsletter is disabled (Settings → Newsletter).'=>'Bouton icône qui ouvre un popover pleine hauteur contenant le formulaire d’inscription à la newsletter. Autonome — insérez-le directement dans un modèle d’en-tête ou de pied de page ; ne s’affiche rien lorsque la newsletter publique est désactivée (Réglages → Newsletter).','block keywordnewsletter'=>'newsletter','block keywordsubscribe'=>'s’abonner','block keywordpopover'=>'popover','block keywordfooter'=>'pied de page','block titleNewsletter Signup'=>'Inscription à la newsletter','block descriptionEmail signup form for the public newsletter (double opt-in). Submits to the newsletter subscribe REST endpoint.'=>'Formulaire d’inscription par e-mail pour la newsletter publique (double opt-in). L’envoi se fait vers le point de terminaison REST d’abonnement à la newsletter.','block keywordsignup'=>'inscription','block titleMy Submissions'=>'Mes soumissions','block descriptionLists the logged-in artist\'s pending artwork submissions for review and approval. Place this on your /my-submissions/ page or in a Site Editor template.'=>'Liste les soumissions d’œuvres en attente de l’artiste connecté pour examen et approbation. Placez ceci sur votre page /my-submissions/ ou dans un modèle de l’éditeur de site.','block keywordsubmissions'=>'soumissions','block keywordreview'=>'examen']];